INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'easy', 'sentence-structure', 'The students finished their exams they celebrated afterward. Which choice best corrects the underlined portion?', 'No change', 'exams, they celebrated', 'exams; they celebrated', 'exams they, celebrated', 'C', 'A semicolon correctly joins two independent clauses without a conjunction.'),
('Grammar', 'easy', 'sentence-structure', 'Running through the park on a sunny afternoon. Which revision makes this a complete sentence?', 'Running through the park on a sunny afternoon, she felt free.', 'Running through the park on a sunny afternoon, felt free.', 'Running through the park. On a sunny afternoon.', 'Through the park on a sunny afternoon running.', 'A', 'A sentence fragment needs a subject and a main verb to become a complete sentence.'),
('Grammar', 'easy', 'sentence-structure', 'Maria likes swimming, hiking, and to ride her bicycle. Which choice corrects the parallel structure?', 'swimming, hiking, and riding her bicycle', 'swimming, hiking, and to ride her bicycle', 'to swim, hiking, and riding her bicycle', 'swimming, to hike, and to ride her bicycle', 'A', 'Items in a list must use the same grammatical form; all three should be gerunds.'),
('Grammar', 'easy', 'sentence-structure', 'The dog barked loudly it woke the neighbors. Which choice best corrects this sentence?', 'The dog barked loudly; it woke the neighbors.', 'The dog barked loudly, it woke the neighbors.', 'The dog barked loudly it, woke the neighbors.', 'The dog barked, loudly it woke the neighbors.', 'A', 'A semicolon correctly separates two related independent clauses.'),
('Grammar', 'easy', 'sentence-structure', 'After finishing the assignment. The student went home. Which revision best corrects this fragment?', 'No change', 'After finishing the assignment; the student went home.', 'After finishing the assignment, the student went home.', 'After finishing. The assignment the student went home.', 'C', 'The introductory dependent clause must be attached to the main clause with a comma.'),
('Grammar', 'easy', 'sentence-structure', 'Jake enjoys reading, writing, and he likes to cook. Which choice uses correct parallel structure?', 'No change', 'reading, writing, and he cooks', 'reading, writing, and cooking', 'to read, writing, and cooking', 'C', 'All items in a series should follow the same grammatical pattern.'),
('Grammar', 'easy', 'sentence-structure', 'The concert was canceled the rain was too heavy. Which is the best revision?', 'The concert was canceled because the rain was too heavy.', 'The concert was canceled, the rain was too heavy.', 'The concert was canceled the rain, was too heavy.', 'The concert, was canceled the rain was too heavy.', 'A', 'A subordinating conjunction like "because" properly connects a cause to its effect.'),
('Grammar', 'easy', 'sentence-structure', 'Because she studied hard. She passed the test. Which revision corrects this error?', 'No change', 'Because she studied hard; she passed the test.', 'Because she studied hard, she passed the test.', 'Because she studied hard she, passed the test.', 'C', 'A dependent clause beginning with "because" must be connected to the independent clause with a comma.'),
('Grammar', 'easy', 'sentence-structure', 'The teacher explained the lesson the students took notes and asked questions. Which is the best revision?', 'No change', 'The teacher explained the lesson, the students took notes and asked questions.', 'The teacher explained the lesson, and the students took notes and asked questions.', 'The teacher explained the lesson the students, took notes and asked questions.', 'C', 'Two independent clauses need a comma and a coordinating conjunction to be joined correctly.'),
('Grammar', 'easy', 'sentence-structure', 'Wanting to arrive early. Luis set three alarms. Which choice corrects this fragment?', 'No change', 'Wanting to arrive early; Luis set three alarms.', 'Wanting to arrive early, Luis set three alarms.', 'Wanting, to arrive early Luis set three alarms.', 'C', 'A participial phrase must be attached to the main clause, typically with a comma.'),
('Grammar', 'easy', 'sentence-structure', 'The students were told to read the chapter, answer the questions, and that they should write a summary. Which choice corrects the parallel structure?', 'No change', 'to read the chapter, answer the questions, and they wrote a summary', 'reading the chapter, answering the questions, and to write a summary', 'read the chapter, answer the questions, and write a summary', 'D', 'All items in a series should use the same verb form for parallel structure.'),
('Grammar', 'easy', 'sentence-structure', 'Sarah went to the store she forgot her wallet. Which is the best way to correct this run-on?', 'Sarah went to the store, but she forgot her wallet.', 'Sarah went to the store she, forgot her wallet.', 'Sarah went to the store she forgot, her wallet.', 'Sarah went, to the store she forgot her wallet.', 'A', 'A comma with a coordinating conjunction correctly joins two independent clauses.'),
('Grammar', 'easy', 'sentence-structure', 'Although the weather was cold. Many people attended the outdoor event. Which revision is correct?', 'Although the weather was cold, many people attended the outdoor event.', 'Although the weather was cold; many people attended the outdoor event.', 'No change', 'Although the weather was cold many, people attended the outdoor event.', 'A', 'A dependent clause must be joined to the main clause, not separated as its own sentence.'),
('Grammar', 'easy', 'sentence-structure', 'The chef prepared the meal it smelled delicious. Which choice best corrects this sentence?', 'No change', 'The chef, prepared the meal it smelled delicious.', 'The chef prepared the meal it, smelled delicious.', 'The chef prepared the meal, and it smelled delicious.', 'D', 'A comma and coordinating conjunction correctly join two independent clauses.'),
('Grammar', 'easy', 'sentence-structure', 'To win the science fair, practice every day, and studying the rubric. Which choice corrects the parallel structure?', 'No change', 'Winning the science fair, practice every day, and study the rubric.', 'To win the science fair, practicing every day, and studying the rubric.', 'To win the science fair, practice every day, and study the rubric.', 'D', 'Imperative verbs in a list should use the same base form for parallel structure.'),
('Grammar', 'easy', 'sentence-structure', 'The library is quiet it is a good place to study. Which revision best corrects this run-on?', 'The library is quiet; it is a good place to study.', 'The library is quiet, it is a good place to study.', 'The library is quiet it, is a good place to study.', 'The library, is quiet it is a good place to study.', 'A', 'A semicolon properly joins two closely related independent clauses.'),
('Grammar', 'easy', 'sentence-structure', 'While walking to school in the morning. Emma noticed the cherry blossoms blooming. Which is the correct revision?', 'No change', 'While walking to school in the morning; Emma noticed the cherry blossoms blooming.', 'While walking to school in the morning, Emma noticed the cherry blossoms blooming.', 'While walking, to school in the morning Emma noticed the cherry blossoms blooming.', 'C', 'An introductory dependent clause should be followed by a comma and then the main clause.'),
('Grammar', 'easy', 'sentence-structure', 'The movie was exciting it kept us on the edge of our seats. Which revision is best?', 'No change', 'The movie was exciting it, kept us on the edge of our seats.', 'The movie was exciting; it kept us on the edge of our seats.', 'The movie, was exciting it kept us on the edge of our seats.', 'C', 'A semicolon correctly separates two independent clauses that are closely related.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'medium', 'sentence-structure', 'The researcher collected data from multiple sources, analyzed the results, and was writing a comprehensive report. Which choice improves parallel structure?', 'No change', 'collected data from multiple sources, analyzed the results, and wrote a comprehensive report', 'collecting data from multiple sources, analyzing the results, and writing a comprehensive report', 'to collect data from multiple sources, to analyze the results, and was writing a comprehensive report', 'B', 'All verbs in a series should be in the same tense for parallel structure; past tense is consistent here.'),
('Grammar', 'medium', 'sentence-structure', 'Exhausted from the long hike, the trail seemed to stretch on forever. Which revision corrects the dangling modifier?', 'No change', 'Exhausted from the long hike, the hikers felt the trail seemed to stretch on forever.', 'The trail seemed to stretch on forever, exhausted from the long hike.', 'Exhausted from the long hike; the trail seemed to stretch on forever.', 'B', 'A dangling modifier must be followed by the noun it logically describes; the hikers are exhausted, not the trail.'),
('Grammar', 'medium', 'sentence-structure', 'The new policy requires employees to submit timesheets weekly, the old policy only required monthly submissions. Which is the best revision?', 'No change', 'The new policy requires employees to submit timesheets weekly; the old policy only required monthly submissions.', 'The new policy requires employees to submit timesheets weekly the old policy only required monthly submissions.', 'The new policy requires employees to submit, timesheets weekly the old policy only required monthly submissions.', 'B', 'A semicolon correctly separates two contrasting independent clauses.'),
('Grammar', 'medium', 'sentence-structure', 'Flying over the mountains, the landscape appeared breathtaking to the passengers. Which revision corrects the misplaced modifier?', 'No change', 'Flying over the mountains; the landscape appeared breathtaking to the passengers.', 'The landscape appeared breathtaking, flying over the mountains to the passengers.', 'Flying over the mountains, the passengers found the landscape breathtaking.', 'D', 'The participial phrase "flying over the mountains" must modify the passengers, not the landscape.'),
('Grammar', 'medium', 'sentence-structure', 'The committee voted to increase funding, to hire new staff, and that they would renovate the building. Which choice corrects the parallel structure?', 'No change', 'to increase funding, to hire new staff, and to renovate the building', 'increasing funding, hiring new staff, and that they would renovate the building', 'to increase funding, hiring new staff, and renovating the building', 'B', 'All items in a series should use the same grammatical form; infinitives are consistent here.'),
('Grammar', 'medium', 'sentence-structure', 'The professor, who specializes in marine biology and has published over fifty papers. Which revision makes this a complete sentence?', 'No change', 'The professor; who specializes in marine biology and has published over fifty papers.', 'The professor who specializes in marine biology and has published over fifty papers.', 'The professor, who specializes in marine biology and has published over fifty papers, is retiring next year.', 'D', 'The original is a fragment because the relative clause replaces the main verb; a predicate is needed.'),
('Grammar', 'medium', 'sentence-structure', 'Painted in vibrant colors, the museum visitors admired the mural. Which revision corrects the dangling modifier?', 'No change', 'Painted in vibrant colors the museum; visitors admired the mural.', 'The museum visitors admired, painted in vibrant colors the mural.', 'Painted in vibrant colors, the mural was admired by the museum visitors.', 'D', 'The modifier "painted in vibrant colors" describes the mural, so the mural must follow the phrase.'),
('Grammar', 'medium', 'sentence-structure', 'The city plans to build new parks, improve public transportation, and the expansion of affordable housing. Which revision uses correct parallel structure?', 'No change', 'to build new parks, to improve public transportation, and the expanding of affordable housing', 'building new parks, improving public transportation, and the expansion of affordable housing', 'build new parks, improve public transportation, and expand affordable housing', 'D', 'All items following "to" should use base-form infinitives for parallel structure.'),
('Grammar', 'medium', 'sentence-structure', 'The report was thorough, however, it contained several factual errors. Which revision is correct?', 'No change', 'The report was thorough however; it contained several factual errors.', 'The report was thorough however it contained several factual errors.', 'The report was thorough; however, it contained several factual errors.', 'D', 'A conjunctive adverb like "however" joining two independent clauses requires a semicolon before it and a comma after.'),
('Grammar', 'medium', 'sentence-structure', 'Known for its innovative designs, many architects study the firm''s portfolio. Which revision corrects the dangling modifier?', 'No change', 'Known for its innovative designs; many architects study the firm''s portfolio.', 'Known for its innovative designs, the firm''s portfolio is studied by many architects.', 'Many architects, known for its innovative designs study the firm''s portfolio.', 'C', 'The modifier "known for its innovative designs" describes the firm''s portfolio, which must immediately follow the phrase.'),
('Grammar', 'medium', 'sentence-structure', 'The athlete trained hard every morning, she also maintained a strict diet. Which is the best revision?', 'No change', 'The athlete trained hard, every morning she also maintained a strict diet.', 'The athlete trained hard every morning she also maintained a strict diet.', 'The athlete trained hard every morning; she also maintained a strict diet.', 'D', 'A semicolon correctly joins two related independent clauses without a conjunction.'),
('Grammar', 'medium', 'sentence-structure', 'The volunteers were asked to sort donations, label boxes, and that they should load the truck. Which revision corrects this sentence?', 'No change', 'sort donations, label boxes, and load the truck', 'sorting donations, labeling boxes, and that they should load the truck', 'to sort donations, to label boxes, and they should load the truck', 'B', 'Items in a series should use the same grammatical form for parallel structure.'),
('Grammar', 'medium', 'sentence-structure', 'Walking through the ancient ruins, a sense of wonder filled the tourists. Which revision corrects the dangling modifier?', 'No change', 'Walking through the ancient ruins; a sense of wonder filled the tourists.', 'A sense of wonder filled the tourists, walking through the ancient ruins.', 'Walking through the ancient ruins, the tourists were filled with a sense of wonder.', 'D', 'The participial phrase must modify the noun performing the action—the tourists, not the sense of wonder.'),
('Grammar', 'medium', 'sentence-structure', 'The company not only increased salaries but also were improving benefits for all employees. Which choice corrects the parallel structure?', 'No change', 'not only was increasing salaries but also improved benefits for all employees', 'not only increased salaries but also improved benefits for all employees', 'not only increasing salaries but also were improving benefits for all employees', 'C', 'Correlative conjunctions (not only...but also) require parallel verb forms on both sides.'),
('Grammar', 'medium', 'sentence-structure', 'The documentary explored the effects of climate change, it also proposed several solutions. Which is the best revision?', 'No change', 'The documentary explored the effects of climate change; it also proposed several solutions.', 'The documentary explored the effects of climate change it also, proposed several solutions.', 'The documentary explored, the effects of climate change it also proposed several solutions.', 'B', 'Two independent clauses cannot be joined by just a comma; a semicolon is appropriate here.'),
('Grammar', 'medium', 'sentence-structure', 'After reviewing the evidence carefully and because the jury deliberated for hours. They reached a unanimous verdict. Which revision is correct?', 'No change', 'After reviewing the evidence carefully; and because the jury deliberated for hours they reached a unanimous verdict.', 'After reviewing the evidence carefully and because the jury deliberated for hours, they reached a unanimous verdict.', 'After reviewing the evidence carefully and deliberating for hours, the jury reached a unanimous verdict.', 'D', 'The original mixes constructions and creates a fragment; a single participial phrase with a clear subject corrects both issues.'),
('Grammar', 'medium', 'sentence-structure', 'Hoping to impress the judges, the routine was performed flawlessly by the gymnast. Which revision corrects the dangling modifier?', 'No change', 'The routine was performed flawlessly, hoping to impress the judges by the gymnast.', 'Hoping to impress the judges, the gymnast performed the routine flawlessly.', 'Hoping to impress the judges; the routine was performed flawlessly by the gymnast.', 'C', 'The phrase "hoping to impress the judges" must be followed by the person doing the hoping—the gymnast.'),
('Grammar', 'medium', 'sentence-structure', 'The manager asked the team to review the proposal, consider the budget, and they should present their findings. Which choice corrects parallel structure?', 'No change', 'to review the proposal, considering the budget, and present their findings', 'reviewing the proposal, considering the budget, and they should present their findings', 'review the proposal, consider the budget, and present their findings', 'D', 'All items in a series following "to" should be base-form verbs for consistent parallel structure.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'hard', 'sentence-structure', 'The senator argued that the bill would reduce costs, create jobs, and that the economy would benefit from increased consumer spending. Which revision best maintains parallel structure while preserving meaning?', 'No change', 'reducing costs, creating jobs, and benefiting the economy through increased consumer spending', 'would reduce costs, would create jobs, and that the economy would benefit from increased consumer spending', 'would reduce costs, create jobs, and benefit the economy through increased consumer spending', 'D', 'The three items after "would" should share that auxiliary verb and use parallel base-form verbs.'),
('Grammar', 'hard', 'sentence-structure', 'Having been developed over the course of a decade by researchers at multiple institutions, the medical community eagerly anticipated the release of the new treatment protocol. Which revision corrects the dangling modifier?', 'No change', 'Having been developed over the course of a decade by researchers at multiple institutions, the new treatment protocol was eagerly anticipated by the medical community.', 'The medical community eagerly anticipated the release of the new treatment protocol, having been developed over the course of a decade by researchers at multiple institutions.', 'Having been developed over the course of a decade; by researchers at multiple institutions the medical community eagerly anticipated the release of the new treatment protocol.', 'B', 'The participial phrase describes the treatment protocol, which must immediately follow the modifier.'),
('Grammar', 'hard', 'sentence-structure', 'The study found that participants who exercised regularly reported lower stress levels, they also demonstrated improved cognitive function, and their overall life satisfaction scores were significantly higher. Which is the most effective revision?', 'No change', 'The study found that participants who exercised regularly reported lower stress levels; demonstrated improved cognitive function; and scored significantly higher on overall life satisfaction.', 'The study found that participants who exercised regularly reported lower stress levels, demonstrated improved cognitive function, and scored significantly higher on overall life satisfaction.', 'The study found that participants who exercised regularly: reported lower stress levels, demonstrated improved cognitive function, scored significantly higher on overall life satisfaction.', 'C', 'A single subject with three parallel predicates joined by commas and "and" is the most concise and grammatically correct structure.'),
('Grammar', 'hard', 'sentence-structure', 'Analyzing the data from three continents and spanning two decades of longitudinal research. The team published findings that contradicted the prevailing scientific consensus. Which revision is correct?', 'No change', 'Analyzing the data from three continents; and spanning two decades of longitudinal research the team published findings that contradicted the prevailing scientific consensus.', 'Analyzing the data from three continents and spanning two decades of longitudinal research, the team published findings that contradicted the prevailing scientific consensus.', 'The team published findings, analyzing the data from three continents and spanning two decades of longitudinal research that contradicted the prevailing scientific consensus.', 'C', 'The participial phrase is a fragment and must be attached to the main clause with a comma.'),
('Grammar', 'hard', 'sentence-structure', 'The architect designed buildings that were not only aesthetically striking but also they were environmentally sustainable and which were constructed using locally sourced materials. Which revision best corrects the parallel structure?', 'No change', 'not only aesthetically striking but also environmentally sustainable and constructed using locally sourced materials', 'not only aesthetically striking but also were environmentally sustainable and were constructed using locally sourced materials', 'not only were aesthetically striking but also environmentally sustainable and constructed with locally sourced materials', 'B', 'After "not only...but also," the adjectives and participle should be parallel without repeating the verb.'),
('Grammar', 'hard', 'sentence-structure', 'Concerned about the declining enrollment figures, a new marketing strategy was implemented by the admissions office that targeted underrepresented communities. Which is the best revision?', 'No change', 'A new marketing strategy was implemented by the admissions office, concerned about the declining enrollment figures, that targeted underrepresented communities.', 'Concerned about the declining enrollment figures, the admissions office implemented a new marketing strategy that targeted underrepresented communities.', 'Concerned about the declining enrollment figures; a new marketing strategy was implemented by the admissions office that targeted underrepresented communities.', 'C', 'The modifier "concerned about declining enrollment" must be followed by the admissions office, which is the entity that is concerned.'),
('Grammar', 'hard', 'sentence-structure', 'The nonprofit organization aims to provide clean water to rural communities, the organization also educates residents about sustainable agricultural practices, and it advocates for policy changes at the national level. Which revision is most concise and correct?', 'No change', 'The nonprofit organization aims to provide clean water to rural communities, educate residents about sustainable agricultural practices, and advocate for policy changes at the national level.', 'The nonprofit organization aims to provide clean water to rural communities; educate residents about sustainable agricultural practices; and advocate for policy changes at the national level.', 'The nonprofit organization: aims to provide clean water to rural communities, educates residents about sustainable agricultural practices, advocates for policy changes at the national level.', 'B', 'The three infinitive phrases should share the verb "aims to" and be listed in parallel without repeating the subject.'),
('Grammar', 'hard', 'sentence-structure', 'Written in haste and without consulting the legal team, the board members were surprised by the numerous errors in the contract. Which revision corrects the dangling modifier?', 'No change', 'Written in haste and without consulting the legal team, the contract surprised the board members with its numerous errors.', 'The board members were surprised by the numerous errors in the contract, written in haste and without consulting the legal team.', 'Written in haste and without consulting the legal team; the board members were surprised by the numerous errors in the contract.', 'B', 'The modifier describes the contract, so the contract must immediately follow the participial phrase.'),
('Grammar', 'hard', 'sentence-structure', 'The program encourages students to think critically, collaborate with peers from diverse backgrounds, and the development of leadership skills that will serve them throughout their careers. Which revision corrects the parallel structure?', 'No change', 'to think critically, to collaborate with peers from diverse backgrounds, and the developing of leadership skills that will serve them throughout their careers', 'thinking critically, collaborating with peers from diverse backgrounds, and the development of leadership skills that will serve them throughout their careers', 'think critically, collaborate with peers from diverse backgrounds, and develop leadership skills that will serve them throughout their careers', 'D', 'After "to," all three items should be base-form verbs for parallel structure.'),
('Grammar', 'hard', 'sentence-structure', 'The governor signed the education reform bill into law on Tuesday, this action followed months of heated debate in the state legislature, the bill had been revised multiple times before gaining bipartisan support. Which is the best revision?', 'No change', 'The governor signed the education reform bill into law on Tuesday; this action followed months of heated debate in the state legislature, the bill had been revised multiple times before gaining bipartisan support.', 'The governor signed the education reform bill into law on Tuesday, this action followed months of heated debate in the state legislature; the bill had been revised multiple times before gaining bipartisan support.', 'The governor signed the education reform bill into law on Tuesday. This action followed months of heated debate in the state legislature, and the bill had been revised multiple times before gaining bipartisan support.', 'D', 'Breaking the run-on into separate sentences and using a conjunction creates clear, grammatical structure.'),
('Grammar', 'hard', 'sentence-structure', 'Neither the principal nor the teachers was aware that the standardized testing schedule, which had been established at the beginning of the year, were going to be changed by the district office. Which revision corrects the errors?', 'No change', 'Neither the principal nor the teachers was aware that the standardized testing schedule, which had been established at the beginning of the year, was going to be changed by the district office.', 'Neither the principal nor the teachers were aware that the standardized testing schedule, which had been established at the beginning of the year, was going to be changed by the district office.', 'Neither the principal nor the teachers were aware that the standardized testing schedule, which had been established at the beginning of the year, were going to be changed by the district office.', 'C', 'With "neither...nor," the verb agrees with the nearer subject (teachers = plural "were"), and "schedule" is singular so takes "was."'),
('Grammar', 'hard', 'sentence-structure', 'Praised by critics for its innovative storytelling, audiences worldwide flocked to see the film during its opening weekend. Which is the best revision?', 'No change', 'Praised by critics for its innovative storytelling, the film attracted audiences worldwide during its opening weekend.', 'Audiences worldwide flocked to see the film during its opening weekend, praised by critics for its innovative storytelling.', 'Praised by critics for its innovative storytelling; audiences worldwide flocked to see the film during its opening weekend.', 'B', 'The phrase "praised by critics" modifies the film, not the audiences, so the film must follow the modifier.'),
('Grammar', 'hard', 'sentence-structure', 'The proposed legislation would both strengthen environmental protections and it would also create new economic incentives for businesses that adopt green technologies. Which revision corrects the parallel structure?', 'No change', 'would both strengthen environmental protections and create new economic incentives for businesses that adopt green technologies', 'both would strengthen environmental protections and would also create new economic incentives for businesses that adopt green technologies', 'would both strengthen environmental protections and would also be creating new economic incentives for businesses that adopt green technologies', 'B', 'With "both...and," parallel structure requires matching verb forms; "would" covers both verbs.'),
('Grammar', 'hard', 'sentence-structure', 'By implementing stricter safety protocols, conducting regular inspections, and because they invested in updated equipment, the factory reduced its accident rate by seventy percent. Which revision corrects the parallel structure?', 'No change', 'By implementing stricter safety protocols, conducting regular inspections, and investing in updated equipment, the factory reduced its accident rate by seventy percent.', 'By implementing stricter safety protocols, by conducting regular inspections, and because they invested in updated equipment, the factory reduced its accident rate by seventy percent.', 'Implementing stricter safety protocols, conducting regular inspections, and because they invested in updated equipment, the factory reduced its accident rate by seventy percent.', 'B', 'All three items after "by" should be gerund phrases for consistent parallel structure.'),
('Grammar', 'hard', 'sentence-structure', 'The investigation revealed that the company had not only violated federal regulations but also that they were engaged in a systematic effort to conceal evidence from auditors. Which is the best revision?', 'No change', 'had not only violated federal regulations but also had been engaged in a systematic effort to conceal evidence from auditors', 'not only had violated federal regulations but also that they were engaged in a systematic effort to conceal evidence from auditors', 'had not only violated federal regulations but also engaged in a systematic effort to conceal evidence from auditors', 'D', 'Correlative conjunctions require parallel forms; both elements share "had" as their auxiliary.'),
('Grammar', 'hard', 'sentence-structure', 'Developed through years of painstaking research and refined by extensive peer review, scientists at the university believe the new climate model represents a significant advancement. Which is the best revision?', 'No change', 'Developed through years of painstaking research and refined by extensive peer review; scientists at the university believe the new climate model represents a significant advancement.', 'Scientists at the university believe the new climate model, developed through years of painstaking research and refined by extensive peer review, represents a significant advancement.', 'Scientists at the university, developed through years of painstaking research and refined by extensive peer review believe the new climate model represents a significant advancement.', 'C', 'The modifier describes the climate model, not the scientists; placing it as an appositive next to "model" corrects the error.'),
('Grammar', 'hard', 'sentence-structure', 'The museum''s new exhibit features artifacts that were discovered during a recent archaeological excavation, it provides visitors with an immersive experience that chronicles the daily life of ancient civilizations, the exhibit has already attracted record attendance. Which is the best revision?', 'No change', 'The museum''s new exhibit features artifacts that were discovered during a recent archaeological excavation; it provides visitors with an immersive experience that chronicles the daily life of ancient civilizations; the exhibit has already attracted record attendance.', 'The museum''s new exhibit features artifacts discovered during a recent archaeological excavation and provides visitors with an immersive experience that chronicles daily life in ancient civilizations. The exhibit has already attracted record attendance.', 'The museum''s new exhibit, features artifacts that were discovered during a recent archaeological excavation it provides visitors with an immersive experience that chronicles the daily life of ancient civilizations the exhibit has already attracted record attendance.', 'C', 'Combining related predicates under one subject and starting a new sentence for the distinct idea creates the clearest structure.'),
('Grammar', 'hard', 'sentence-structure', 'To prepare for the international summit, the delegation reviewed policy briefings, consulted with economic advisors, and extensive practice sessions for the multilingual presentations were conducted. Which revision corrects the parallel structure?', 'No change', 'to review policy briefings, to consult with economic advisors, and extensive practice sessions for the multilingual presentations were conducted', 'reviewing policy briefings, consulting with economic advisors, and extensive practice sessions for the multilingual presentations were conducted', 'reviewed policy briefings, consulted with economic advisors, and conducted extensive practice sessions for the multilingual presentations', 'D', 'All three items should be past-tense verbs with the same subject for consistent parallel structure.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'easy', 'punctuation', 'The students who studied for the exam, passed with high scores. Which choice correctly punctuates this sentence?', 'No change', 'The students, who studied for the exam passed with high scores.', 'The students who studied for the exam passed with high scores.', 'The students who studied, for the exam passed with high scores.', 'C', 'A restrictive clause ("who studied for the exam") should not be set off by commas because it is essential to the meaning.'),
('Grammar', 'easy', 'punctuation', 'My brother who lives in Texas is visiting next week. Which choice is correctly punctuated if the writer has only one brother?', 'No change', 'My brother, who lives in Texas is visiting next week.', 'My brother, who lives in Texas, is visiting next week.', 'My brother who lives in Texas, is visiting next week.', 'C', 'When the writer has only one brother, the clause is nonrestrictive and must be set off by commas on both sides.'),
('Grammar', 'easy', 'punctuation', 'The recipe calls for three ingredients: flour, sugar, and butter. Is this sentence punctuated correctly?', 'No change', 'The recipe calls for three ingredients, flour, sugar, and butter.', 'The recipe calls for three ingredients; flour, sugar, and butter.', 'The recipe calls for three ingredients flour, sugar, and butter.', 'A', 'A colon correctly introduces a list that follows a complete independent clause.'),
('Grammar', 'easy', 'punctuation', 'Its important to proofread your work before submitting it. Which choice corrects the punctuation error?', 'No change', 'Its'' important to proofread your work before submitting it.', 'It''s important to proofread your work before submitting it.', 'Its, important to proofread your work before submitting it.', 'C', '"It''s" is the contraction for "it is," which is needed here; "its" is the possessive form.'),
('Grammar', 'easy', 'punctuation', 'The dog wagged its'' tail happily. Which choice is correct?', 'No change', 'The dog wagged it''s tail happily.', 'The dog wagged its tail happily.', 'The dog wagged its, tail happily.', 'C', 'The possessive form of "it" is "its" with no apostrophe.'),
('Grammar', 'easy', 'punctuation', 'After the game we went out for pizza. Which choice is correctly punctuated?', 'No change', 'After the game, we went out for pizza.', 'After, the game we went out for pizza.', 'After the game; we went out for pizza.', 'B', 'A comma should follow an introductory prepositional phrase.'),
('Grammar', 'easy', 'punctuation', 'The childrens'' toys were scattered across the floor. Which choice is correct?', 'No change', 'The children''s toys were scattered across the floor.', 'The childrens toys were scattered across the floor.', 'The children toys'' were scattered across the floor.', 'B', '"Children" is already plural, so the possessive is formed by adding ''s.'),
('Grammar', 'easy', 'punctuation', 'She packed her suitcase, however, she forgot her passport. Which choice is correctly punctuated?', 'No change', 'She packed her suitcase, however she forgot her passport.', 'She packed her suitcase however she forgot her passport.', 'She packed her suitcase; however, she forgot her passport.', 'D', 'A conjunctive adverb like "however" between independent clauses requires a semicolon before and a comma after.'),
('Grammar', 'easy', 'punctuation', 'The stores hours are 9 AM to 5 PM. Which choice corrects the punctuation?', 'No change', 'The stores, hours are 9 AM to 5 PM.', 'The stores'' hours are 9 AM to 5 PM.', 'The store''s hours are 9 AM to 5 PM.', 'D', 'The singular possessive of "store" requires an apostrophe before the s.'),
('Grammar', 'easy', 'punctuation', 'Yes I would like to attend the meeting. Which choice is correctly punctuated?', 'No change', 'Yes; I would like to attend the meeting.', 'Yes, I would like to attend the meeting.', 'Yes I, would like to attend the meeting.', 'C', 'An introductory word like "yes" should be followed by a comma.'),
('Grammar', 'easy', 'punctuation', 'The teacher said "please open your textbooks." Which choice is correctly punctuated?', 'No change', 'The teacher said, "please open your textbooks."', 'The teacher said, "Please open your textbooks."', 'The teacher, said "Please open your textbooks."', 'C', 'A comma precedes a direct quotation, and the first word of the quotation is capitalized.'),
('Grammar', 'easy', 'punctuation', 'The concert which was held outdoors was canceled due to rain. Which choice is correctly punctuated if the clause is nonrestrictive?', 'No change', 'The concert, which was held outdoors, was canceled due to rain.', 'The concert which was held outdoors, was canceled due to rain.', 'The concert, which was held outdoors was canceled due to rain.', 'B', 'A nonrestrictive clause must be enclosed by commas on both sides.'),
('Grammar', 'easy', 'punctuation', 'The companys profits increased last quarter. Which choice corrects the punctuation?', 'No change', 'The companies profits increased last quarter.', 'The company''s profits increased last quarter.', 'The companys'' profits increased last quarter.', 'C', 'The singular possessive of "company" requires an apostrophe before the s.'),
('Grammar', 'easy', 'punctuation', 'We need to buy the following items milk, eggs, and bread. Which choice is correctly punctuated?', 'No change', 'We need to buy the following items; milk, eggs, and bread.', 'We need to buy the following items: milk, eggs, and bread.', 'We need to buy, the following items milk, eggs, and bread.', 'C', 'A colon correctly introduces a list after a complete independent clause.'),
('Grammar', 'easy', 'punctuation', 'Mr. Johnson the principal addressed the students at the assembly. Which choice is correctly punctuated?', 'No change', 'Mr. Johnson, the principal, addressed the students at the assembly.', 'Mr. Johnson the principal, addressed the students at the assembly.', 'Mr. Johnson, the principal addressed the students at the assembly.', 'B', 'An appositive phrase ("the principal") must be set off by commas on both sides.'),
('Grammar', 'easy', 'punctuation', 'In 2024 the company expanded to three new cities. Which choice is correctly punctuated?', 'No change', 'In, 2024 the company expanded to three new cities.', 'In 2024; the company expanded to three new cities.', 'In 2024, the company expanded to three new cities.', 'D', 'A comma should follow an introductory prepositional phrase.'),
('Grammar', 'easy', 'punctuation', 'The womens restroom is on the second floor. Which choice corrects the possessive form?', 'No change', 'The women''s restroom is on the second floor.', 'The womens'' restroom is on the second floor.', 'The woman''s restroom is on the second floor.', 'B', '"Women" is already plural, so the possessive is formed by adding ''s.'),
('Grammar', 'easy', 'punctuation', 'She is a talented, young musician. Is this comma usage correct if "talented" and "young" are coordinate adjectives?', 'No change', 'She is a talented young musician.', 'She is a talented; young musician.', 'She is a, talented young musician.', 'A', 'When two adjectives independently modify the same noun and can be joined by "and," a comma between them is correct.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'medium', 'punctuation', 'The experiment yielded surprising results; namely, the control group outperformed the test group in every metric. Is this punctuated correctly?', 'No change', 'The experiment yielded surprising results, namely, the control group outperformed the test group in every metric.', 'The experiment yielded surprising results: namely, the control group outperformed the test group in every metric.', 'The experiment yielded surprising results namely; the control group outperformed the test group in every metric.', 'C', 'A colon is preferred before "namely" when it introduces an explanation of the preceding clause.'),
('Grammar', 'medium', 'punctuation', 'The author''s latest novel—a sprawling epic set during the Civil War—has received critical acclaim. Is this punctuated correctly?', 'No change', 'The author''s latest novel, a sprawling epic set during the Civil War, has received critical acclaim.', 'The author''s latest novel; a sprawling epic set during the Civil War; has received critical acclaim.', 'The author''s latest novel—a sprawling epic set during the Civil War, has received critical acclaim.', 'A', 'Em dashes correctly set off an appositive phrase, especially for emphasis; this is properly punctuated.'),
('Grammar', 'medium', 'punctuation', 'The three companies'' CEO''s met to discuss the merger. Which choice corrects the possessive forms?', 'No change', 'The three companies'' CEOs met to discuss the merger.', 'The three companies'' CEOs'' met to discuss the merger.', 'The three company''s CEOs met to discuss the merger.', 'B', 'The plural possessive of "companies" is "companies''," and "CEOs" as a simple plural needs no apostrophe.'),
('Grammar', 'medium', 'punctuation', 'The students'' research focused on one central question: how does social media affect adolescent mental health? Is this punctuated correctly?', 'No change', 'The students'' research focused on one central question; how does social media affect adolescent mental health?', 'The students'' research focused on one central question, how does social media affect adolescent mental health?', 'The students'' research focused on one central question—how does social media affect adolescent mental health.', 'A', 'A colon correctly introduces a question that elaborates on the preceding clause.'),
('Grammar', 'medium', 'punctuation', 'The CEO, along with several board members were present at the shareholder meeting. Which choice is correctly punctuated?', 'No change', 'The CEO along with several board members were present at the shareholder meeting.', 'The CEO, along with several board members, were present at the shareholder meeting.', 'The CEO along with several board members, were present at the shareholder meeting.', 'C', 'The parenthetical phrase "along with several board members" must be set off by commas on both sides.'),
('Grammar', 'medium', 'punctuation', 'The researchers findings—which contradicted earlier studies—prompted a re-evaluation of the original hypothesis. Which choice corrects the possessive?', 'No change', 'The researchers'' findings—which contradicted earlier studies—prompted a re-evaluation of the original hypothesis.', 'The researcher''s findings—which contradicted earlier studies—prompted a re-evaluation of the original hypothesis.', 'The researchers findings, which contradicted earlier studies, prompted a re-evaluation of the original hypothesis.', 'B', 'If multiple researchers are involved, "researchers''" (plural possessive) is needed; if one, "researcher''s" (C) would be correct. Context suggests plural.'),
('Grammar', 'medium', 'punctuation', 'The project has three phases, planning, execution, and evaluation. Which choice is correctly punctuated?', 'No change', 'The project has three phases: planning, execution, and evaluation.', 'The project has three phases; planning, execution, and evaluation.', 'The project has three phases—planning execution and evaluation.', 'B', 'A colon introduces a list when preceded by a complete independent clause.'),
('Grammar', 'medium', 'punctuation', 'James who is my oldest friend is moving to Portland, Oregon next month. Which choice is correctly punctuated?', 'No change', 'James, who is my oldest friend is moving to Portland, Oregon, next month.', 'James, who is my oldest friend, is moving to Portland, Oregon, next month.', 'James who is my oldest friend, is moving to Portland Oregon, next month.', 'C', 'The nonrestrictive clause needs commas on both sides, and "Portland, Oregon" requires a comma after the state when the sentence continues.'),
('Grammar', 'medium', 'punctuation', 'The museum''s collection includes works by Monet, Renoir, and Degas, however, the Impressionist wing is currently closed for renovation. Which choice is correctly punctuated?', 'No change', 'The museum''s collection includes works by Monet, Renoir, and Degas however, the Impressionist wing is currently closed for renovation.', 'The museum''s collection includes works by Monet, Renoir, and Degas; however, the Impressionist wing is currently closed for renovation.', 'The museum''s collection includes works by Monet; Renoir; and Degas, however, the Impressionist wing is currently closed for renovation.', 'C', 'A semicolon before "however" and a comma after it correctly join two independent clauses with a conjunctive adverb.'),
('Grammar', 'medium', 'punctuation', 'The manager asked, "Has everyone submitted their reports"? Which choice is correctly punctuated?', 'No change', 'The manager asked, "Has everyone submitted their reports"!', 'The manager asked "Has everyone submitted their reports?"', 'The manager asked, "Has everyone submitted their reports?"', 'D', 'The question mark belongs inside the quotation marks because it is part of the quoted question.'),
('Grammar', 'medium', 'punctuation', 'The well known author released her highly anticipated novel last Tuesday. Which choice is correctly punctuated?', 'No change', 'The well-known author released her highly-anticipated novel last Tuesday.', 'The well-known author released her highly anticipated novel last Tuesday.', 'The well known author released her highly-anticipated novel last Tuesday.', 'C', '"Well-known" requires a hyphen as a compound modifier before a noun, but "highly anticipated" does not because adverbs ending in -ly are not hyphenated.'),
('Grammar', 'medium', 'punctuation', 'The scholarship is available to students, who maintain a GPA above 3.5. Which choice is correctly punctuated if the clause is restrictive?', 'No change', 'The scholarship is available to students who maintain a GPA above 3.5.', 'The scholarship is available to students; who maintain a GPA above 3.5.', 'The scholarship is available, to students who maintain a GPA above 3.5.', 'B', 'A restrictive clause essential to the sentence''s meaning should not be preceded by a comma.'),
('Grammar', 'medium', 'punctuation', 'The teams'' performance this season has been exceptional: they''ve won ten consecutive games. Is this punctuated correctly if referring to one team?', 'No change', 'The teams performance this season has been exceptional: they''ve won ten consecutive games.', 'The team''s performance this season has been exceptional: they''ve won ten consecutive games.', 'The team''s performance this season has been exceptional; they''ve won ten consecutive games.', 'C', 'For a single team, the possessive is "team''s" (singular possessive with apostrophe before s).'),
('Grammar', 'medium', 'punctuation', 'The report concluded with a stark warning, "Without immediate action, the consequences will be irreversible." Which choice is correctly punctuated?', 'No change', 'The report concluded with a stark warning "Without immediate action, the consequences will be irreversible."', 'The report concluded with a stark warning; "Without immediate action, the consequences will be irreversible."', 'The report concluded with a stark warning: "Without immediate action, the consequences will be irreversible."', 'D', 'A colon properly introduces a quotation that follows an independent clause.'),
('Grammar', 'medium', 'punctuation', 'The internship offers several benefits, including: mentorship, professional development, and networking opportunities. Which choice is correctly punctuated?', 'No change', 'The internship offers several benefits including; mentorship, professional development, and networking opportunities.', 'The internship offers several benefits; including mentorship, professional development, and networking opportunities.', 'The internship offers several benefits, including mentorship, professional development, and networking opportunities.', 'D', 'A colon should not follow "including" because it already serves as the list introducer; removing the colon is correct.'),
('Grammar', 'medium', 'punctuation', 'The candidate promised to lower taxes, improve healthcare and invest in education. Which choice uses the Oxford comma correctly?', 'No change', 'The candidate promised to lower taxes, improve healthcare, and invest in education.', 'The candidate promised to lower taxes improve healthcare and invest in education.', 'The candidate promised to: lower taxes, improve healthcare, and invest in education.', 'B', 'The Oxford (serial) comma before "and" in a list of three or more items prevents ambiguity.'),
('Grammar', 'medium', 'punctuation', 'The twenty five year old entrepreneur launched her start up from her parents garage. Which choice correctly uses hyphens and apostrophes?', 'No change', 'The twenty-five-year-old entrepreneur launched her start-up from her parents'' garage.', 'The twenty-five year old entrepreneur launched her start-up from her parent''s garage.', 'The twenty five-year-old entrepreneur launched her startup from her parents'' garage.', 'B', 'Compound adjectives before a noun are hyphenated, "start-up" is hyphenated, and the plural possessive of "parents" is "parents''."'),
('Grammar', 'medium', 'punctuation', 'The festival, which takes place every July attracts thousands of visitors from around the world. Which choice is correctly punctuated?', 'No change', 'The festival which takes place every July, attracts thousands of visitors from around the world.', 'The festival, which takes place every July, attracts thousands of visitors from around the world.', 'The festival; which takes place every July, attracts thousands of visitors from around the world.', 'C', 'A nonrestrictive clause must be enclosed by commas on both sides.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'hard', 'punctuation', 'The study''s authors—Dr. Patel, a neurologist, Dr. Kim, a psychiatrist, and Dr. Rivera, a psychologist—presented their findings at the conference. Which choice best clarifies the list?', 'No change', 'The study''s authors: Dr. Patel, a neurologist, Dr. Kim, a psychiatrist, and Dr. Rivera, a psychologist, presented their findings at the conference.', 'The study''s authors—Dr. Patel, a neurologist; Dr. Kim, a psychiatrist; and Dr. Rivera, a psychologist—presented their findings at the conference.', 'The study''s authors; Dr. Patel, a neurologist, Dr. Kim, a psychiatrist, and Dr. Rivera, a psychologist; presented their findings at the conference.', 'C', 'When list items already contain commas, semicolons are used to separate the items for clarity.'),
('Grammar', 'hard', 'punctuation', 'The company''s mission statement emphasizes three core values: integrity, the foundation of all its business dealings; innovation, which drives its competitive edge; and sustainability, a commitment to future generations. Is this punctuated correctly?', 'No change', 'The company''s mission statement emphasizes three core values: integrity, the foundation of all its business dealings, innovation, which drives its competitive edge, and sustainability, a commitment to future generations.', 'The company''s mission statement emphasizes three core values; integrity, the foundation of all its business dealings; innovation, which drives its competitive edge; and sustainability, a commitment to future generations.', 'The company''s mission statement emphasizes three core values: integrity—the foundation of all its business dealings, innovation—which drives its competitive edge, and sustainability—a commitment to future generations.', 'A', 'The colon introduces the list, and semicolons correctly separate items that contain internal commas.'),
('Grammar', 'hard', 'punctuation', 'The professors'' lecture notes—which had been meticulously compiled over two decades and were considered invaluable by graduate students''—were accidentally deleted from the server. Which choice corrects the punctuation?', 'No change', 'The professor''s lecture notes, which had been meticulously compiled over two decades and were considered invaluable by graduate students, were accidentally deleted from the server.', 'The professors'' lecture notes—which had been meticulously compiled over two decades and were considered invaluable by graduate students—were accidentally deleted from the server.', 'The professors'' lecture notes—which had been meticulously compiled over two decades, and were considered invaluable by graduate students—were accidentally deleted from the server.', 'C', 'The closing em dash should match the opening one without an erroneous apostrophe after "students."'),
('Grammar', 'hard', 'punctuation', 'The diplomat made one thing clear, the negotiations would not resume until both parties agreed to a ceasefire; a condition that had proven elusive in previous rounds of talks. Which choice is correctly punctuated?', 'No change', 'The diplomat made one thing clear: the negotiations would not resume until both parties agreed to a ceasefire, a condition that had proven elusive in previous rounds of talks.', 'The diplomat made one thing clear; the negotiations would not resume until both parties agreed to a ceasefire, a condition that had proven elusive in previous rounds of talks.', 'The diplomat made one thing clear: the negotiations would not resume until both parties agreed to a ceasefire; a condition that had proven elusive in previous rounds of talks.', 'B', 'A colon introduces the explanation, and "a condition..." is an appositive modifying "ceasefire," requiring a comma, not a semicolon.'),
('Grammar', 'hard', 'punctuation', 'The orchestra performed works by three composers, Bach, whose fugues demand technical precision, Beethoven, whose symphonies require emotional depth, and Stravinsky, whose rhythms challenge even seasoned musicians. Which choice best clarifies the punctuation?', 'No change', 'The orchestra performed works by three composers; Bach, whose fugues demand technical precision, Beethoven, whose symphonies require emotional depth, and Stravinsky, whose rhythms challenge even seasoned musicians.', 'The orchestra performed works by three composers: Bach, whose fugues demand technical precision; Beethoven, whose symphonies require emotional depth; and Stravinsky, whose rhythms challenge even seasoned musicians.', 'The orchestra performed works by three composers: Bach whose fugues demand technical precision, Beethoven whose symphonies require emotional depth, and Stravinsky whose rhythms challenge even seasoned musicians.', 'C', 'A colon introduces the list, and semicolons separate items that contain internal commas for clarity.'),
('Grammar', 'hard', 'punctuation', 'The CEO announced the restructuring plan—one that would affect nearly half the workforce—during the quarterly earnings call, a move that analysts described as "bold but risky". Which choice is correctly punctuated?', 'No change', 'The CEO announced the restructuring plan—one that would affect nearly half the workforce—during the quarterly earnings call, a move that analysts described as "bold but risky."', 'The CEO announced the restructuring plan, one that would affect nearly half the workforce, during the quarterly earnings call—a move that analysts described as "bold but risky."', 'The CEO announced the restructuring plan—one that would affect nearly half the workforce—during the quarterly earnings call; a move that analysts described as "bold but risky."', 'B', 'In American English, the period goes inside the quotation marks.'),
('Grammar', 'hard', 'punctuation', 'The researcher''s hypothesis was straightforward; if air pollution levels decreased, then respiratory illness rates would decline proportionally, however, the data told a more complicated story. Which choice is correctly punctuated?', 'No change', 'The researcher''s hypothesis was straightforward: if air pollution levels decreased, then respiratory illness rates would decline proportionally, however, the data told a more complicated story.', 'The researcher''s hypothesis was straightforward, if air pollution levels decreased, then respiratory illness rates would decline proportionally; however, the data told a more complicated story.', 'The researcher''s hypothesis was straightforward: if air pollution levels decreased, then respiratory illness rates would decline proportionally. However, the data told a more complicated story.', 'D', 'A colon introduces the hypothesis, and "however" starting a contrasting independent clause works best as a new sentence.'),
('Grammar', 'hard', 'punctuation', 'The novel—which critics have called "a masterpiece of modern fiction"—explores themes of identity, belonging, and the immigrant experience in twenty first century America. Which choice corrects all punctuation errors?', 'No change', 'The novel—which critics have called "a masterpiece of modern fiction"—explores themes of identity, belonging, and the immigrant experience in twenty-first-century America.', 'The novel, which critics have called "a masterpiece of modern fiction," explores themes of identity, belonging, and the immigrant experience in twenty first-century America.', 'The novel—which critics have called "a masterpiece of modern fiction"—explores themes of identity, belonging, and the immigrant experience in twenty-first century America.', 'B', '"Twenty-first-century" is a compound adjective modifying "America" and needs hyphens throughout.'),
('Grammar', 'hard', 'punctuation', 'The galleries'' newest acquisitions include paintings by three artists: Yayoi Kusama, known for her infinity rooms, Banksy, the anonymous street artist, and Jean-Michel Basquiat, whose neo-expressionist works command record prices. Which choice best clarifies the list?', 'No change', 'The galleries'' newest acquisitions include paintings by three artists: Yayoi Kusama—known for her infinity rooms—Banksy—the anonymous street artist—and Jean-Michel Basquiat—whose neo-expressionist works command record prices.', 'The galleries'' newest acquisitions include paintings by three artists, Yayoi Kusama known for her infinity rooms, Banksy the anonymous street artist, and Jean-Michel Basquiat whose neo-expressionist works command record prices.', 'The galleries'' newest acquisitions include paintings by three artists: Yayoi Kusama, known for her infinity rooms; Banksy, the anonymous street artist; and Jean-Michel Basquiat, whose neo-expressionist works command record prices.', 'D', 'Semicolons separate list items that already contain commas, providing clarity.'),
('Grammar', 'hard', 'punctuation', 'The architects'' design incorporated several innovative features, for example: solar panels integrated into the facade, a rainwater collection system, and geothermal heating. Which choice is correctly punctuated?', 'No change', 'The architects'' design incorporated several innovative features—for example, solar panels integrated into the facade, a rainwater collection system, and geothermal heating.', 'The architects'' design incorporated several innovative features, for example, solar panels integrated into the facade, a rainwater collection system, and geothermal heating.', 'The architects'' design incorporated several innovative features: for example, solar panels integrated into the facade, a rainwater collection system, and geothermal heating.', 'D', 'A colon introduces the elaboration, and "for example" is set off by a comma, not preceded by a colon itself.'),
('Grammar', 'hard', 'punctuation', 'The committees'' decision—which was reached after a marathon twelve hour session and was immediately criticized by the opposition—will take effect on January 1, 2026. Which choice corrects all errors?', 'No change', 'The committee''s decision—which was reached after a marathon twelve hour session, and was immediately criticized by the opposition—will take effect on January 1, 2026.', 'The committees'' decision, which was reached after a marathon twelve-hour session and was immediately criticized by the opposition, will take effect on January 1, 2026.', 'The committee''s decision—which was reached after a marathon twelve-hour session and was immediately criticized by the opposition—will take effect on January 1, 2026.', 'D', 'Assuming one committee, the possessive is "committee''s," and "twelve-hour" is a compound adjective requiring a hyphen.'),
('Grammar', 'hard', 'punctuation', 'The keynote speaker made a provocative claim, "The era of traditional banking," she declared, "is effectively over". Which choice is correctly punctuated?', 'No change', 'The keynote speaker made a provocative claim: "The era of traditional banking," she declared, "is effectively over."', 'The keynote speaker made a provocative claim; "The era of traditional banking," she declared, "is effectively over."', 'The keynote speaker made a provocative claim "The era of traditional banking" she declared "is effectively over."', 'B', 'A colon introduces the quotation after an independent clause, and in American English the period goes inside the closing quotation mark.'),
('Grammar', 'hard', 'punctuation', 'The school board voted to approve the budget, which includes funding for three initiatives, a new STEM lab, an expanded arts program, and additional counseling staff, despite objections from several community members. Which choice best clarifies the punctuation?', 'No change', 'The school board voted to approve the budget—which includes funding for three initiatives: a new STEM lab, an expanded arts program, and additional counseling staff—despite objections from several community members.', 'The school board voted to approve the budget, which includes funding for three initiatives; a new STEM lab; an expanded arts program; and additional counseling staff, despite objections from several community members.', 'The school board voted to approve the budget, which includes funding for three initiatives: a new STEM lab, an expanded arts program, and additional counseling staff; despite objections from several community members.', 'B', 'Em dashes set off the parenthetical, and a colon introduces the list within it, creating the clearest structure.'),
('Grammar', 'hard', 'punctuation', 'The documentary examines three interconnected crises; climate change, which threatens coastal cities, biodiversity loss, which destabilizes ecosystems, and water scarcity, which affects billions. Which choice is correctly punctuated?', 'No change', 'The documentary examines three interconnected crises: climate change, which threatens coastal cities; biodiversity loss, which destabilizes ecosystems; and water scarcity, which affects billions.', 'The documentary examines three interconnected crises, climate change, which threatens coastal cities, biodiversity loss, which destabilizes ecosystems, and water scarcity, which affects billions.', 'The documentary examines three interconnected crises: climate change which threatens coastal cities, biodiversity loss which destabilizes ecosystems, and water scarcity which affects billions.', 'B', 'A colon introduces the list, and semicolons separate items containing internal commas.'),
('Grammar', 'hard', 'punctuation', 'The professor emphasized that the students'' theses—each of which must be at least fifty pages long, include original research, and be defended before a three person committee—are due by May 15. Which choice corrects all errors?', 'No change', 'The professor emphasized that the student''s theses—each of which must be at least fifty pages long, include original research, and be defended before a three person committee—are due by May 15.', 'The professor emphasized that the students'' theses—each of which must be at least fifty pages long, include original research, and be defended before a three-person committee—are due by May 15.', 'The professor emphasized that the students'' theses, each of which must be at least fifty pages long, include original research, and be defended before a three-person committee, are due by May 15.', 'C', '"Three-person" is a compound adjective requiring a hyphen; the rest of the punctuation is correct.'),
('Grammar', 'hard', 'punctuation', 'The investor''s strategy was simple; yet effective, buy undervalued stocks, hold them for at least five years, and sell only when the market reaches historically high levels. Which choice is correctly punctuated?', 'No change', 'The investor''s strategy was simple yet effective: buy undervalued stocks, hold them for at least five years, and sell only when the market reaches historically high levels.', 'The investor''s strategy was simple, yet effective; buy undervalued stocks, hold them for at least five years, and sell only when the market reaches historically high levels.', 'The investor''s strategy was simple yet effective, buy undervalued stocks, hold them for at least five years, and sell only when the market reaches historically high levels.', 'B', '"Simple yet effective" needs no internal punctuation, and a colon introduces the list that explains the strategy.'),
('Grammar', 'hard', 'punctuation', 'Three factors contributed to the projects'' failure, inadequate funding, poor leadership, and a lack of clear objectives, all of which the auditors'' report documented in detail. Which choice corrects the punctuation?', 'No change', 'Three factors contributed to the project''s failure: inadequate funding, poor leadership, and a lack of clear objectives, all of which the auditors'' report documented in detail.', 'Three factors contributed to the project''s failure—inadequate funding, poor leadership, and a lack of clear objectives—all of which the auditor''s report documented in detail.', 'Three factors contributed to the project''s failure: inadequate funding, poor leadership, and a lack of clear objectives—all of which the auditors'' report documented in detail.', 'D', 'A colon introduces the list, and an em dash sets off the concluding appositive clause; "project''s" is singular possessive.'),
('Grammar', 'hard', 'punctuation', 'The alumni associations'' annual gala—which raised over $2 million for scholarships last year—will feature performances by Grammy winning artists and a keynote address by the university''s president. Which choice corrects all errors?', 'No change', 'The alumni association''s annual gala—which raised over $2 million for scholarships last year—will feature performances by Grammy winning artists, and a keynote address by the university''s president.', 'The alumni associations'' annual gala, which raised over $2 million for scholarships last year, will feature performances by Grammy-winning artists and a keynote address by the university''s president.', 'The alumni association''s annual gala—which raised over $2 million for scholarships last year—will feature performances by Grammy-winning artists and a keynote address by the university''s president.', 'D', '"Association''s" is singular possessive, and "Grammy-winning" is a compound adjective requiring a hyphen.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'easy', 'subject-verb-agreement', 'The box of chocolates are on the table. Which choice corrects the verb agreement?', 'No change', 'The box of chocolates is on the table.', 'The box of chocolates were on the table.', 'The box of chocolates have been on the table.', 'B', 'The subject is "box" (singular), not "chocolates," so the verb must be singular: "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The team are preparing for the championship game. Which choice is correct in American English?', 'No change', 'The team have been preparing for the championship game.', 'The team were preparing for the championship game.', 'The team is preparing for the championship game.', 'D', 'In American English, collective nouns like "team" take a singular verb.'),
('Grammar', 'easy', 'subject-verb-agreement', 'Neither the teacher nor the students was ready for the fire drill. Which choice corrects the verb agreement?', 'No change', 'Neither the teacher nor the students has been ready for the fire drill.', 'Neither the teacher nor the students is ready for the fire drill.', 'Neither the teacher nor the students were ready for the fire drill.', 'D', 'With "neither...nor," the verb agrees with the nearer subject; "students" is plural, so "were" is correct.'),
('Grammar', 'easy', 'subject-verb-agreement', 'Each of the players have received a trophy. Which choice corrects the verb agreement?', 'No change', 'Each of the players has received a trophy.', 'Each of the players were receiving a trophy.', 'Each of the players are receiving a trophy.', 'B', '"Each" is a singular indefinite pronoun and requires a singular verb: "has."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The news about the storms are alarming. Which choice corrects the verb agreement?', 'No change', 'The news about the storms have been alarming.', 'The news about the storms were alarming.', 'The news about the storms is alarming.', 'D', '"News" is a singular noun despite ending in -s, so it requires the singular verb "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'Bread and butter are my favorite breakfast. Which choice is correct when referring to a single item?', 'No change', 'Bread and butter were my favorite breakfast.', 'Bread and butter is my favorite breakfast.', 'Bread and butter have been my favorite breakfast.', 'C', 'When "bread and butter" refers to a single concept (one item), it takes a singular verb.'),
('Grammar', 'easy', 'subject-verb-agreement', 'The group of tourists are visiting the museum today. Which choice corrects the verb agreement?', 'No change', 'The group of tourists is visiting the museum today.', 'The group of tourists were visiting the museum today.', 'The group of tourists have visited the museum today.', 'B', 'The subject is "group" (singular), so the verb must be singular: "is visiting."'),
('Grammar', 'easy', 'subject-verb-agreement', 'Every student and teacher have signed the petition. Which choice corrects the verb agreement?', 'No change', 'Every student and teacher has signed the petition.', 'Every student and teacher were signing the petition.', 'Every student and teacher are signing the petition.', 'B', '"Every" makes each noun singular, so the compound subject takes a singular verb: "has."'),
('Grammar', 'easy', 'subject-verb-agreement', 'Mathematics are my favorite subject. Which choice corrects the verb agreement?', 'No change', 'Mathematics have been my favorite subject.', 'Mathematics were my favorite subject.', 'Mathematics is my favorite subject.', 'D', '"Mathematics" is singular despite ending in -s and requires the singular verb "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The list of items need to be checked. Which choice corrects the verb agreement?', 'No change', 'The list of items were needing to be checked.', 'The list of items needs to be checked.', 'The list of items are needing to be checked.', 'C', 'The subject is "list" (singular), not "items," so the verb must be singular: "needs."'),
('Grammar', 'easy', 'subject-verb-agreement', 'There is many reasons to visit the national park. Which choice corrects the verb agreement?', 'No change', 'There has been many reasons to visit the national park.', 'There are many reasons to visit the national park.', 'There was many reasons to visit the national park.', 'C', 'In an inverted sentence beginning with "there," the verb agrees with the true subject "reasons" (plural).'),
('Grammar', 'easy', 'subject-verb-agreement', 'The committee have reached a decision. Which choice is correct in American English?', 'No change', 'The committee were reaching a decision.', 'The committee has reached a decision.', 'The committee are reaching a decision.', 'C', 'In American English, "committee" is a collective noun that takes a singular verb: "has."'),
('Grammar', 'easy', 'subject-verb-agreement', 'Either the cat or the dogs is responsible for the mess. Which choice corrects the verb agreement?', 'No change', 'Either the cat or the dogs has been responsible for the mess.', 'Either the cat or the dogs was responsible for the mess.', 'Either the cat or the dogs are responsible for the mess.', 'D', 'With "either...or," the verb agrees with the nearer subject; "dogs" is plural, so "are" is correct.'),
('Grammar', 'easy', 'subject-verb-agreement', 'One of the windows are broken. Which choice corrects the verb agreement?', 'No change', 'One of the windows have been broken.', 'One of the windows were broken.', 'One of the windows is broken.', 'D', '"One" is a singular subject, so the verb must be singular: "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The family are going on vacation next week. Which choice is correct in American English?', 'No change', 'The family were going on vacation next week.', 'The family is going on vacation next week.', 'The family have gone on vacation next week.', 'C', 'In American English, "family" as a collective noun acting as a unit takes a singular verb: "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'Five dollars are too much for a cup of coffee. Which choice corrects the verb agreement?', 'No change', 'Five dollars have been too much for a cup of coffee.', 'Five dollars were too much for a cup of coffee.', 'Five dollars is too much for a cup of coffee.', 'D', 'When referring to a sum of money as a single amount, it takes a singular verb: "is."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The stack of books on the shelf need to be organized. Which choice corrects the verb agreement?', 'No change', 'The stack of books on the shelf needs to be organized.', 'The stack of books on the shelf were needing to be organized.', 'The stack of books on the shelf are to be organized.', 'B', 'The subject is "stack" (singular), not "books," so the verb must be singular: "needs."'),
('Grammar', 'easy', 'subject-verb-agreement', 'The audience were clapping enthusiastically. Which choice is correct in American English?', 'No change', 'The audience have clapped enthusiastically.', 'The audience was clapping enthusiastically.', 'The audience are clapping enthusiastically.', 'C', 'In American English, "audience" acting as a single group takes a singular verb: "was."');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'medium', 'subject-verb-agreement', 'The number of applicants for the position have increased dramatically this year. Which choice corrects the verb agreement?', 'No change', 'The number of applicants for the position are increasing dramatically this year.', 'The number of applicants for the position were increasing dramatically this year.', 'The number of applicants for the position has increased dramatically this year.', 'D', '"The number of" is a singular expression requiring a singular verb; contrast with "a number of," which is plural.'),
('Grammar', 'medium', 'subject-verb-agreement', 'A number of students in the advanced chemistry class is planning to attend the conference. Which choice corrects the verb agreement?', 'No change', 'A number of students in the advanced chemistry class has planned to attend the conference.', 'A number of students in the advanced chemistry class was planning to attend the conference.', 'A number of students in the advanced chemistry class are planning to attend the conference.', 'D', '"A number of" functions as a plural expression meaning "several," so it requires a plural verb.'),
('Grammar', 'medium', 'subject-verb-agreement', 'The director, along with the producers and the lead actors, are expected to attend the premiere. Which choice corrects the verb agreement?', 'No change', 'The director, along with the producers and the lead actors, have been expected to attend the premiere.', 'The director, along with the producers and the lead actors, were expected to attend the premiere.', 'The director, along with the producers and the lead actors, is expected to attend the premiere.', 'D', 'Phrases like "along with" do not create a compound subject; the verb agrees with "director" (singular).'),
('Grammar', 'medium', 'subject-verb-agreement', 'Politics are a frequent topic of conversation at family dinners. Which choice corrects the verb agreement?', 'No change', 'Politics were a frequent topic of conversation at family dinners.', 'Politics is a frequent topic of conversation at family dinners.', 'Politics have been a frequent topic of conversation at family dinners.', 'C', 'When "politics" refers to the field or subject, it is singular and takes a singular verb.'),
('Grammar', 'medium', 'subject-verb-agreement', 'Neither the manager nor any of the employees has access to the secure server room. Is this correct?', 'No change', 'Neither the manager nor any of the employees are to have access to the secure server room.', 'Neither the manager nor any of the employees were having access to the secure server room.', 'Neither the manager nor any of the employees have access to the secure server room.', 'D', 'With "neither...nor," the verb agrees with the nearer subject; "employees" is plural, so "have" is correct.'),
('Grammar', 'medium', 'subject-verb-agreement', 'The majority of the evidence presented during the trial point to the defendant''s innocence. Which choice corrects the verb agreement?', 'No change', 'The majority of the evidence presented during the trial points to the defendant''s innocence.', 'The majority of the evidence presented during the trial were pointing to the defendant''s innocence.', 'The majority of the evidence presented during the trial have pointed to the defendant''s innocence.', 'B', '"Evidence" is an uncountable noun, so "the majority of the evidence" takes a singular verb: "points."'),
('Grammar', 'medium', 'subject-verb-agreement', 'Every one of the contestants who auditioned for the show were given a callback. Which choice corrects the verb agreement?', 'No change', 'Every one of the contestants who auditioned for the show was given a callback.', 'Every one of the contestants who auditioned for the show have been given a callback.', 'Every one of the contestants who auditioned for the show are given a callback.', 'B', '"Every one" is singular and takes a singular verb: "was."'),
('Grammar', 'medium', 'subject-verb-agreement', 'The economics of running a small business is complex and often discouraging. Which choice corrects the verb agreement?', 'No change', 'The economics of running a small business were complex and often discouraging.', 'The economics of running a small business are complex and often discouraging.', 'The economics of running a small business has been complex and often discouraging.', 'C', 'When "economics" refers to practical financial matters rather than the academic field, it can be plural: "are."'),
('Grammar', 'medium', 'subject-verb-agreement', 'Not only the students but also the professor were surprised by the results of the experiment. Which choice corrects the verb agreement?', 'No change', 'Not only the students but also the professor have been surprised by the results of the experiment.', 'Not only the students but also the professor was surprised by the results of the experiment.', 'Not only the students but also the professor are surprised by the results of the experiment.', 'C', 'With "not only...but also," the verb agrees with the nearer subject; "professor" is singular, so "was" is correct.'),
('Grammar', 'medium', 'subject-verb-agreement', 'Ten miles are a long distance to run without training. Which choice corrects the verb agreement?', 'No change', 'Ten miles were a long distance to run without training.', 'Ten miles is a long distance to run without training.', 'Ten miles have been a long distance to run without training.', 'C', 'When a measurement refers to a single unit or concept, it takes a singular verb: "is."'),
('Grammar', 'medium', 'subject-verb-agreement', 'The data from the recent surveys suggests that consumer confidence is declining. Which choice uses the correct verb form?', 'No change', 'The data from the recent surveys suggest that consumer confidence is declining.', 'The data from the recent surveys has suggested that consumer confidence is declining.', 'The data from the recent surveys were suggesting that consumer confidence is declining.', 'B', 'In formal and scientific writing, "data" is treated as plural (the plural of "datum") and takes "suggest."'),
('Grammar', 'medium', 'subject-verb-agreement', 'Either the senator or her aides is expected to issue a statement by this afternoon. Which choice corrects the verb agreement?', 'No change', 'Either the senator or her aides has been expected to issue a statement by this afternoon.', 'Either the senator or her aides was expected to issue a statement by this afternoon.', 'Either the senator or her aides are expected to issue a statement by this afternoon.', 'D', 'With "either...or," the verb agrees with the nearer subject; "aides" is plural, so "are" is correct.'),
('Grammar', 'medium', 'subject-verb-agreement', 'The choir, as well as the orchestra, are performing at the annual gala this Saturday. Which choice corrects the verb agreement?', 'No change', 'The choir, as well as the orchestra, were performing at the annual gala this Saturday.', 'The choir, as well as the orchestra, is performing at the annual gala this Saturday.', 'The choir, as well as the orchestra, have been performing at the annual gala this Saturday.', 'C', '"As well as" does not form a compound subject; the verb agrees with "choir" (singular): "is."'),
('Grammar', 'medium', 'subject-verb-agreement', 'None of the information provided by the witnesses were accurate. Which choice corrects the verb agreement?', 'No change', 'None of the information provided by the witnesses was accurate.', 'None of the information provided by the witnesses have been accurate.', 'None of the information provided by the witnesses are accurate.', 'B', '"Information" is uncountable, so "none of the information" takes a singular verb: "was."'),
('Grammar', 'medium', 'subject-verb-agreement', 'The criteria for admission has been clearly stated in the application guidelines. Which choice corrects the verb agreement?', 'No change', 'The criteria for admission is clearly stated in the application guidelines.', 'The criteria for admission was clearly stated in the application guidelines.', 'The criteria for admission have been clearly stated in the application guidelines.', 'D', '"Criteria" is the plural of "criterion" and requires a plural verb: "have been."'),
('Grammar', 'medium', 'subject-verb-agreement', 'There is, in addition to the main attractions, several smaller exhibits worth visiting. Which choice corrects the verb agreement?', 'No change', 'There are, in addition to the main attractions, several smaller exhibits worth visiting.', 'There has been, in addition to the main attractions, several smaller exhibits worth visiting.', 'There was, in addition to the main attractions, several smaller exhibits worth visiting.', 'B', 'The true subject is "exhibits" (plural), so the verb must be plural: "are."'),
('Grammar', 'medium', 'subject-verb-agreement', 'Two-thirds of the forest have been destroyed by the wildfire. Which choice corrects the verb agreement?', 'No change', 'Two-thirds of the forest are destroyed by the wildfire.', 'Two-thirds of the forest were destroyed by the wildfire.', 'Two-thirds of the forest has been destroyed by the wildfire.', 'D', 'With fractions, the verb agrees with the object of "of"; "forest" is singular, so the verb is singular: "has been."'),
('Grammar', 'medium', 'subject-verb-agreement', 'A series of earthquakes have rattled the region over the past month. Which choice corrects the verb agreement?', 'No change', 'A series of earthquakes are rattling the region over the past month.', 'A series of earthquakes were rattling the region over the past month.', 'A series of earthquakes has rattled the region over the past month.', 'D', '"A series" is singular and takes a singular verb: "has rattled."');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'hard', 'subject-verb-agreement', 'The phenomenon of tidal waves, which are caused by underwater seismic activity and have been studied extensively by marine geologists, remain poorly understood by the general public. Which choice corrects the verb agreement?', 'No change', 'The phenomenon of tidal waves, which are caused by underwater seismic activity and have been studied extensively by marine geologists, have remained poorly understood by the general public.', 'The phenomenon of tidal waves, which is caused by underwater seismic activity and has been studied extensively by marine geologists, remain poorly understood by the general public.', 'The phenomenon of tidal waves, which are caused by underwater seismic activity and have been studied extensively by marine geologists, remains poorly understood by the general public.', 'D', 'The main subject is "phenomenon" (singular), so the main verb must be "remains"; the relative clause verbs correctly agree with "waves."'),
('Grammar', 'hard', 'subject-verb-agreement', 'Neither the complexity of the equations nor the volume of data that must be processed present an insurmountable challenge to experienced researchers. Which choice is correct?', 'No change', 'Neither the complexity of the equations nor the volume of data that must be processed presents an insurmountable challenge to experienced researchers.', 'Neither the complexity of the equations nor the volume of data that must be processed have presented an insurmountable challenge to experienced researchers.', 'Neither the complexity of the equations nor the volume of data that must be processed are presenting an insurmountable challenge to experienced researchers.', 'B', 'With "neither...nor," the verb agrees with the nearer subject; "volume" is singular, so "presents" is correct.'),
('Grammar', 'hard', 'subject-verb-agreement', 'The collection of rare manuscripts, along with several first-edition novels that were donated by the estate, are being cataloged by the university''s archival team. Which choice corrects the verb agreement?', 'No change', 'The collection of rare manuscripts, along with several first-edition novels that were donated by the estate, were being cataloged by the university''s archival team.', 'The collection of rare manuscripts, along with several first-edition novels that were donated by the estate, is being cataloged by the university''s archival team.', 'The collection of rare manuscripts, along with several first-edition novels that were donated by the estate, have been cataloged by the university''s archival team.', 'C', '"Along with" does not create a compound subject; the verb agrees with "collection" (singular): "is being."'),
('Grammar', 'hard', 'subject-verb-agreement', 'Each of the proposals submitted by the competing firms, which range in cost from $2 million to $10 million, have merit. Which choice corrects the verb agreement?', 'No change', 'Each of the proposals submitted by the competing firms, which range in cost from $2 million to $10 million, has merit.', 'Each of the proposals submitted by the competing firms, which ranges in cost from $2 million to $10 million, have merit.', 'Each of the proposals submitted by the competing firms, which range in cost from $2 million to $10 million, are having merit.', 'B', '"Each" is singular and requires "has"; the relative clause verb "range" correctly agrees with "proposals."'),
('Grammar', 'hard', 'subject-verb-agreement', 'The media''s coverage of the protests, which have spread to cities across the country, have been criticized for its lack of objectivity. Which choice corrects the verb agreement?', 'No change', 'The media''s coverage of the protests, which have spread to cities across the country, has been criticized for its lack of objectivity.', 'The media''s coverage of the protests, which has spread to cities across the country, have been criticized for its lack of objectivity.', 'The media''s coverage of the protests, which have spread to cities across the country, were criticized for its lack of objectivity.', 'B', 'The main subject is "coverage" (singular), so the main verb is "has been"; "have spread" correctly agrees with "protests."'),
('Grammar', 'hard', 'subject-verb-agreement', 'Not only the athletes who competed in the marathon but also the coach who trained them for months deserve recognition for the team''s unprecedented success. Which choice is correct?', 'No change', 'Not only the athletes who competed in the marathon but also the coach who trained them for months deserves recognition for the team''s unprecedented success.', 'Not only the athletes who competed in the marathon but also the coach who trained them for months has deserved recognition for the team''s unprecedented success.', 'Not only the athletes who competed in the marathon but also the coach who trained them for months are deserving recognition for the team''s unprecedented success.', 'B', 'With "not only...but also," the verb agrees with the nearer subject; "coach" is singular, so "deserves" is correct.'),
('Grammar', 'hard', 'subject-verb-agreement', 'The variety of courses offered by the department, including several that were recently added to address emerging fields of study, make the program attractive to prospective students. Which choice corrects the verb agreement?', 'No change', 'The variety of courses offered by the department, including several that were recently added to address emerging fields of study, makes the program attractive to prospective students.', 'The variety of courses offered by the department, including several that were recently added to address emerging fields of study, have made the program attractive to prospective students.', 'The variety of courses offered by the department, including several that were recently added to address emerging fields of study, are making the program attractive to prospective students.', 'B', '"The variety of" is a singular expression, so the main verb must be "makes."'),
('Grammar', 'hard', 'subject-verb-agreement', 'One in five Americans who participate in the annual health survey report experiencing chronic pain. Which choice corrects the verb agreement?', 'No change', 'One in five Americans who participates in the annual health survey reports experiencing chronic pain.', 'One in five Americans who participates in the annual health survey report experiencing chronic pain.', 'One in five Americans who participate in the annual health survey reports experiencing chronic pain.', 'D', '"One" is the subject and is singular, requiring "reports"; "who participate" correctly agrees with "Americans."'),
('Grammar', 'hard', 'subject-verb-agreement', 'The implications of the Supreme Court''s ruling, which experts predict will affect millions of citizens and reshape the legal landscape for decades, remains a subject of intense debate. Which choice corrects the verb agreement?', 'No change', 'The implications of the Supreme Court''s ruling, which experts predicts will affect millions of citizens and reshape the legal landscape for decades, remains a subject of intense debate.', 'The implications of the Supreme Court''s ruling, which experts predict will affect millions of citizens and reshape the legal landscape for decades, has remained a subject of intense debate.', 'The implications of the Supreme Court''s ruling, which experts predict will affect millions of citizens and reshape the legal landscape for decades, remain a subject of intense debate.', 'D', 'The subject is "implications" (plural), so the main verb must be "remain."'),
('Grammar', 'hard', 'subject-verb-agreement', 'The percentage of students who graduate within four years vary significantly across different departments within the university. Which choice corrects the verb agreement?', 'No change', 'The percentage of students who graduate within four years have varied significantly across different departments within the university.', 'The percentage of students who graduates within four years vary significantly across different departments within the university.', 'The percentage of students who graduate within four years varies significantly across different departments within the university.', 'D', '"The percentage" is singular, so the main verb is "varies"; "who graduate" correctly agrees with "students."'),
('Grammar', 'hard', 'subject-verb-agreement', 'Neither the CEO nor the board members, who were appointed just last quarter and are still acclimating to their roles, has publicly commented on the merger. Which choice corrects the verb agreement?', 'No change', 'Neither the CEO nor the board members, who was appointed just last quarter and is still acclimating to their roles, has publicly commented on the merger.', 'Neither the CEO nor the board members, who were appointed just last quarter and are still acclimating to their roles, have publicly commented on the merger.', 'Neither the CEO nor the board members, who were appointed just last quarter and are still acclimating to their roles, is publicly commenting on the merger.', 'C', 'With "neither...nor," the verb agrees with the nearer subject; "board members" is plural, so "have" is correct.'),
('Grammar', 'hard', 'subject-verb-agreement', 'The orchestra, together with a chorus of one hundred voices that have been rehearsing since September, are scheduled to perform the symphony''s world premiere. Which choice corrects the verb agreement?', 'No change', 'The orchestra, together with a chorus of one hundred voices that have been rehearsing since September, were scheduled to perform the symphony''s world premiere.', 'The orchestra, together with a chorus of one hundred voices that has been rehearsing since September, are scheduled to perform the symphony''s world premiere.', 'The orchestra, together with a chorus of one hundred voices that have been rehearsing since September, is scheduled to perform the symphony''s world premiere.', 'D', '"Together with" does not form a compound subject; the verb agrees with "orchestra" (singular): "is scheduled."'),
('Grammar', 'hard', 'subject-verb-agreement', 'Every student who has submitted their application and completed the required interviews are eligible for the scholarship. Which choice corrects the verb agreement?', 'No change', 'Every student who has submitted their application and completed the required interviews is eligible for the scholarship.', 'Every student who have submitted their application and completed the required interviews are eligible for the scholarship.', 'Every student who has submitted their application and completed the required interviews were eligible for the scholarship.', 'B', '"Every student" is singular and requires a singular main verb: "is eligible."'),
('Grammar', 'hard', 'subject-verb-agreement', 'The hypothesis, supported by data from experiments that span three continents and include over ten thousand participants, have yet to be replicated in a controlled laboratory setting. Which choice corrects the verb agreement?', 'No change', 'The hypothesis, supported by data from experiments that span three continents and include over ten thousand participants, has yet to be replicated in a controlled laboratory setting.', 'The hypothesis, supported by data from experiments that spans three continents and includes over ten thousand participants, have yet to be replicated in a controlled laboratory setting.', 'The hypothesis, supported by data from experiments that span three continents and include over ten thousand participants, are yet to be replicated in a controlled laboratory setting.', 'B', 'The main subject is "hypothesis" (singular), requiring "has"; "that span" and "include" correctly agree with "experiments."'),
('Grammar', 'hard', 'subject-verb-agreement', 'A growing body of research, including studies that challenge long-held assumptions about nutrition, suggest that dietary fat is not as harmful as previously believed. Which choice corrects the verb agreement?', 'No change', 'A growing body of research, including studies that challenge long-held assumptions about nutrition, have suggested that dietary fat is not as harmful as previously believed.', 'A growing body of research, including studies that challenges long-held assumptions about nutrition, suggest that dietary fat is not as harmful as previously believed.', 'A growing body of research, including studies that challenge long-held assumptions about nutrition, suggests that dietary fat is not as harmful as previously believed.', 'D', '"A growing body" is singular, requiring "suggests"; the parenthetical phrase does not change the main subject.'),
('Grammar', 'hard', 'subject-verb-agreement', 'The series of lectures, which was organized by the department and were attended by students from multiple disciplines, have generated significant academic discussion. Which choice corrects all verb agreement errors?', 'No change', 'The series of lectures, which was organized by the department and was attended by students from multiple disciplines, has generated significant academic discussion.', 'The series of lectures, which were organized by the department and were attended by students from multiple disciplines, has generated significant academic discussion.', 'The series of lectures, which were organized by the department and was attended by students from multiple disciplines, have generated significant academic discussion.', 'C', '"Which" refers to "lectures" (plural) so the relative clause verbs should be "were organized" and "were attended"; "series" is singular, so "has generated."'),
('Grammar', 'hard', 'subject-verb-agreement', 'The analysis of the samples, which were collected from sites that spans the entire coastline, reveal patterns consistent with rising ocean temperatures. Which choice corrects all verb agreement errors?', 'No change', 'The analysis of the samples, which were collected from sites that spans the entire coastline, reveal patterns consistent with rising ocean temperatures.', 'The analysis of the samples, which was collected from sites that span the entire coastline, reveals patterns consistent with rising ocean temperatures.', 'The analysis of the samples, which were collected from sites that span the entire coastline, reveals patterns consistent with rising ocean temperatures.', 'D', '"Analysis" is singular requiring "reveals"; "which" refers to "samples" (plural, "were collected"); "that" refers to "sites" (plural, "span").'),
('Grammar', 'hard', 'subject-verb-agreement', 'There exist, despite the skepticism of many established scientists and the lack of institutional funding, a small but dedicated group of researchers investigating the phenomenon. Which choice corrects the verb agreement?', 'No change', 'There are existing, despite the skepticism of many established scientists and the lack of institutional funding, a small but dedicated group of researchers investigating the phenomenon.', 'There have existed, despite the skepticism of many established scientists and the lack of institutional funding, a small but dedicated group of researchers investigating the phenomenon.', 'There exists, despite the skepticism of many established scientists and the lack of institutional funding, a small but dedicated group of researchers investigating the phenomenon.', 'D', 'In this inverted sentence, the true subject is "a small but dedicated group" (singular), so "exists" is correct.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'easy', 'pronoun-clarity', 'When Sarah told Maria about the promotion, she was thrilled. Which revision clarifies the ambiguous pronoun?', 'No change', 'When Sarah told Maria about the promotion, Maria was thrilled.', 'When Sarah told Maria about the promotion, she were thrilled.', 'When Sarah told Maria about the promotion, them was thrilled.', 'B', 'Replacing the ambiguous "she" with a specific name clarifies who was thrilled.'),
('Grammar', 'easy', 'pronoun-clarity', 'Everyone should bring their own lunch to the field trip. Is the pronoun usage correct?', 'No change', 'Everyone should bring his or her own lunch to the field trip.', 'Everyone should bring its own lunch to the field trip.', 'Everyone should bring our own lunch to the field trip.', 'A', 'The singular "they/their" is now widely accepted in formal English to refer to "everyone."'),
('Grammar', 'easy', 'pronoun-clarity', 'The teacher gave the student their grade report. Which choice clarifies this sentence if there is one student?', 'No change', 'The teacher gave the student his grade report.', 'The teacher gave the student her grade report.', 'The teacher gave the student the student''s grade report.', 'D', 'Repeating the noun eliminates the ambiguity of whether "their" refers to the teacher or student.'),
('Grammar', 'easy', 'pronoun-clarity', 'The person who I spoke to was very helpful. Which choice corrects the pronoun?', 'No change', 'The person whose I spoke to was very helpful.', 'The person which I spoke to was very helpful.', 'The person whom I spoke to was very helpful.', 'D', '"Whom" is the objective case pronoun needed here because it is the object of "spoke to."'),
('Grammar', 'easy', 'pronoun-clarity', 'Each of the girls must complete their assignment by Friday. Which choice corrects the pronoun agreement?', 'No change', 'Each of the girls must complete her assignment by Friday.', 'Each of the girls must complete its assignment by Friday.', 'Each of the girls must complete our assignment by Friday.', 'B', '"Each" is singular and in formal writing takes a singular pronoun; "her" matches the female antecedent.'),
('Grammar', 'easy', 'pronoun-clarity', 'The company announced that they would be closing the downtown office. Which choice corrects the pronoun agreement?', 'No change', 'The company announced that it would be closing the downtown office.', 'The company announced that he would be closing the downtown office.', 'The company announced that them would be closing the downtown office.', 'B', '"Company" is a singular noun and should be referred to with the singular pronoun "it."'),
('Grammar', 'easy', 'pronoun-clarity', 'Who did the manager hire for the position? Which choice corrects the pronoun?', 'No change', 'Which did the manager hire for the position?', 'Whose did the manager hire for the position?', 'Whom did the manager hire for the position?', 'D', '"Whom" is correct because it functions as the object of the verb "hire."'),
('Grammar', 'easy', 'pronoun-clarity', 'Tom told Jerry that his car needed repairs. Which revision eliminates the ambiguity?', 'No change', 'Tom told Jerry that it''s car needed repairs.', 'Tom told Jerry that their car needed repairs.', 'Tom told Jerry that Tom''s car needed repairs.', 'D', 'Replacing the ambiguous "his" with a specific name clarifies whose car is being discussed.'),
('Grammar', 'easy', 'pronoun-clarity', 'The committee made their decision. Which choice uses the correct pronoun in American English?', 'No change', 'The committee made our decision.', 'The committee made his decision.', 'The committee made its decision.', 'D', 'In American English, a collective noun like "committee" takes the singular pronoun "its."'),
('Grammar', 'easy', 'pronoun-clarity', 'Neither of the boys brought their textbook to class. Which choice corrects the pronoun agreement?', 'No change', 'Neither of the boys brought our textbook to class.', 'Neither of the boys brought its textbook to class.', 'Neither of the boys brought his textbook to class.', 'D', '"Neither" is singular and requires a singular pronoun: "his."'),
('Grammar', 'easy', 'pronoun-clarity', 'The dog chased it''s tail around the yard. Which choice corrects the pronoun?', 'No change', 'The dog chased its tail around the yard.', 'The dog chased its'' tail around the yard.', 'The dog chased their tail around the yard.', 'B', '"Its" (no apostrophe) is the possessive pronoun; "it''s" is a contraction of "it is."'),
('Grammar', 'easy', 'pronoun-clarity', 'Give the award to whomever deserves it most. Which choice corrects the pronoun?', 'No change', 'Give the award to whom deserves it most.', 'Give the award to whomever it deserves most.', 'Give the award to whoever deserves it most.', 'D', '"Whoever" is correct because it is the subject of the clause "whoever deserves it most."'),
('Grammar', 'easy', 'pronoun-clarity', 'The store raised their prices again. Which choice corrects the pronoun agreement?', 'No change', 'The store raised its prices again.', 'The store raised his prices again.', 'The store raised our prices again.', 'B', '"Store" is singular and should take the singular pronoun "its."'),
('Grammar', 'easy', 'pronoun-clarity', 'Alex asked Pat to help with their homework. Which revision clarifies the ambiguous pronoun?', 'No change', 'Alex asked Pat to help with Alex''s homework.', 'Alex asked Pat to help with them homework.', 'Alex asked Pat to help with its homework.', 'B', 'Replacing the ambiguous "their" with a specific name clarifies whose homework is meant.'),
('Grammar', 'easy', 'pronoun-clarity', 'The jury reached their verdict after three days of deliberation. Which choice uses the correct pronoun in American English?', 'No change', 'The jury reached its verdict after three days of deliberation.', 'The jury reached his verdict after three days of deliberation.', 'The jury reached our verdict after three days of deliberation.', 'B', 'In American English, "jury" acting as a unit takes the singular pronoun "its."'),
('Grammar', 'easy', 'pronoun-clarity', 'Somebody left their umbrella in the hallway. Is this pronoun usage acceptable?', 'No change', 'Somebody left his umbrella in the hallway.', 'Somebody left her umbrella in the hallway.', 'Somebody left its umbrella in the hallway.', 'A', 'Singular "they/their" is accepted in modern standard English when the gender of the antecedent is unknown.'),
('Grammar', 'easy', 'pronoun-clarity', 'The man who the police arrested was later released. Which choice corrects the pronoun?', 'No change', 'The man whose the police arrested was later released.', 'The man which the police arrested was later released.', 'The man whom the police arrested was later released.', 'D', '"Whom" is correct because it is the object of the verb "arrested."'),
('Grammar', 'easy', 'pronoun-clarity', 'The bird built it''s nest in the oak tree. Which choice corrects the pronoun?', 'No change', 'The bird built its'' nest in the oak tree.', 'The bird built its nest in the oak tree.', 'The bird built their nest in the oak tree.', 'C', '"Its" (no apostrophe) is the correct possessive form; "it''s" means "it is."');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'medium', 'pronoun-clarity', 'When the ambassador met with the prime minister, he expressed concerns about the trade agreement. Which revision best eliminates the ambiguity?', 'No change', 'When the ambassador met with the prime minister, the ambassador expressed concerns about the trade agreement.', 'When the ambassador met with the prime minister, they expressed concerns about the trade agreement.', 'When the ambassador met with the prime minister, whom expressed concerns about the trade agreement.', 'B', 'Replacing the ambiguous "he" with the specific noun "the ambassador" clarifies the subject.'),
('Grammar', 'medium', 'pronoun-clarity', 'The students in the advanced placement class must submit his or her portfolio by December. Which choice is most appropriate for formal writing?', 'No change', 'The students in the advanced placement class must submit their portfolios by December.', 'The students in the advanced placement class must submit its portfolio by December.', 'The students in the advanced placement class must submit our portfolios by December.', 'B', '"Students" is plural and requires the plural pronoun "their" with the plural "portfolios."'),
('Grammar', 'medium', 'pronoun-clarity', 'The researcher to who the grant was awarded will present her findings next month. Which choice corrects the pronoun?', 'No change', 'The researcher to whose the grant was awarded will present her findings next month.', 'The researcher to whom the grant was awarded will present her findings next month.', 'The researcher to whoever the grant was awarded will present her findings next month.', 'C', '"Whom" is required as the object of the preposition "to."'),
('Grammar', 'medium', 'pronoun-clarity', 'The professor told the teaching assistant that he needed to revise the syllabus. Which revision best eliminates the ambiguity?', 'No change', 'The professor told the teaching assistant to revise the syllabus.', 'The professor told the teaching assistant that they needed to revise the syllabus.', 'The professor told the teaching assistant that it needed to revise the syllabus.', 'B', 'Restructuring the sentence to remove the pronoun entirely eliminates the ambiguity about who needs to revise.'),
('Grammar', 'medium', 'pronoun-clarity', 'The firm announced that they were relocating their headquarters to Austin. Which choice corrects the pronoun agreement?', 'No change', 'The firm announced that he was relocating their headquarters to Austin.', 'The firm announced that it was relocating its headquarters to Austin.', 'The firm announced that it was relocating their headquarters to Austin.', 'C', '"Firm" is singular and takes singular pronouns "it" and "its" consistently.'),
('Grammar', 'medium', 'pronoun-clarity', 'The candidate whom the committee selected, and who most voters also preferred, withdrew from the race unexpectedly. Is this sentence correct?', 'No change', 'The candidate who the committee selected, and who most voters also preferred, withdrew from the race unexpectedly.', 'The candidate whom the committee selected, and whom most voters also preferred, withdrew from the race unexpectedly.', 'The candidate which the committee selected, and who most voters also preferred, withdrew from the race unexpectedly.', 'A', '"Whom" is correct as the object of "selected," and "who" is correct as the subject of "preferred."'),
('Grammar', 'medium', 'pronoun-clarity', 'After the scientists published their paper, it attracted considerable attention, which led to them receiving additional funding. Which choice improves clarity?', 'No change', 'After the scientists published their paper, it attracted considerable attention, leading it to receive additional funding.', 'After the scientists published their paper, it attracted considerable attention, which led to it receiving additional funding.', 'After the scientists published their paper, the paper attracted considerable attention, which led to the scientists receiving additional funding.', 'D', 'Replacing the vague pronouns "it" and "them" with specific nouns eliminates ambiguity.'),
('Grammar', 'medium', 'pronoun-clarity', 'Neither the CEO nor the managers believe that their approach is wrong. Which choice correctly handles pronoun agreement?', 'No change', 'Neither the CEO nor the managers believe that his approach is wrong.', 'Neither the CEO nor the managers believes that their approach is wrong.', 'Neither the CEO nor the managers believe that its approach is wrong.', 'A', 'With "neither...nor," the verb and pronoun agree with the nearer subject "managers" (plural), making "their" correct.'),
('Grammar', 'medium', 'pronoun-clarity', 'The novel is about a character that struggles with their identity in a rapidly changing society. Which choice is the most appropriate revision?', 'No change', 'The novel is about a character who struggles with their identity in a rapidly changing society.', 'The novel is about a character which struggles with their identity in a rapidly changing society.', 'The novel is about a character whom struggles with their identity in a rapidly changing society.', 'B', '"Who" (not "that" or "which") is the preferred pronoun for referring to people.'),
('Grammar', 'medium', 'pronoun-clarity', 'The principal informed the teacher that her classroom would be renovated over the summer. Which revision eliminates the ambiguity?', 'No change', 'The principal informed the teacher that the teacher''s classroom would be renovated over the summer.', 'The principal informed the teacher that their classroom would be renovated over the summer.', 'The principal informed the teacher that its classroom would be renovated over the summer.', 'B', 'Replacing the ambiguous "her" with the specific noun phrase eliminates the question of whose classroom.'),
('Grammar', 'medium', 'pronoun-clarity', 'Whoever the voters choose as their representative will face significant challenges. Is this sentence correct?', 'No change', 'Whomever the voters choose as its representative will face significant challenges.', 'Whoever the voters choose as his or her representative will face significant challenges.', 'Whomever the voters choose as their representative will face significant challenges.', 'D', '"Whomever" is the object of "choose"; the clause "whomever the voters choose" functions as the subject of "will face."'),
('Grammar', 'medium', 'pronoun-clarity', 'The report emphasized that each employee must take responsibility for their own professional development. Is this pronoun usage correct in modern standard English?', 'No change', 'The report emphasized that each employee must take responsibility for his own professional development.', 'The report emphasized that each employee must take responsibility for its own professional development.', 'The report emphasized that each employee must take responsibility for our own professional development.', 'A', 'Singular "their" is now accepted in modern standard English as a gender-neutral pronoun for "each employee."'),
('Grammar', 'medium', 'pronoun-clarity', 'When the coach met with the player, he discussed the upcoming strategy changes. Which revision best eliminates the ambiguity?', 'No change', 'When the coach met with the player, them discussed the upcoming strategy changes.', 'When the coach met with the player, the coach discussed the upcoming strategy changes.', 'When the coach met with the player, whom discussed the upcoming strategy changes.', 'C', 'Replacing the ambiguous "he" with "the coach" clarifies who is doing the discussing.'),
('Grammar', 'medium', 'pronoun-clarity', 'The museum displayed artifacts from the ancient city, and they were remarkably well preserved. Which revision clarifies the pronoun?', 'No change', 'The museum displayed artifacts from the ancient city, and it were remarkably well preserved.', 'The museum displayed artifacts from the ancient city, and the artifacts were remarkably well preserved.', 'The museum displayed artifacts from the ancient city, and its were remarkably well preserved.', 'C', 'Replacing the vague "they" with "the artifacts" clarifies what was well preserved.'),
('Grammar', 'medium', 'pronoun-clarity', 'The student whom the professor recommended, and who I also found impressive, received the fellowship. Which choice corrects the pronoun error?', 'No change', 'The student whom the professor recommended, and whom I also found impressive, received the fellowship.', 'The student who the professor recommended, and who I also found impressive, received the fellowship.', 'The student whom the professor recommended, and who I also found impressive, received the fellowship.', 'A', '"Whom" is correct as the object of "recommended," and "who" is correct as a subject complement with "found impressive" (objective "whom" could also work here, but "who" is acceptable in modern usage).'),
('Grammar', 'medium', 'pronoun-clarity', 'The corporation increased profits, but they did so by cutting employee benefits. Which revision improves pronoun clarity?', 'No change', 'The corporation increased profits, but whom did so by cutting employee benefits.', 'The corporation increased profits, but them did so by cutting employee benefits.', 'The corporation increased profits, but it did so by cutting employee benefits.', 'D', '"Corporation" is singular and should be referred to as "it," not "they."'),
('Grammar', 'medium', 'pronoun-clarity', 'The architects showed the clients their designs for the new building. Which revision eliminates the ambiguity?', 'No change', 'The architects showed the clients the architects'' designs for the new building.', 'The architects showed the clients them designs for the new building.', 'The architects showed the clients its designs for the new building.', 'B', 'Replacing the ambiguous "their" with a specific noun phrase clarifies whose designs are meant.'),
('Grammar', 'medium', 'pronoun-clarity', 'The scholarship will be awarded to whomever writes the best essay. Which choice corrects the pronoun?', 'No change', 'The scholarship will be awarded to whom writes the best essay.', 'The scholarship will be awarded to whoever writes the best essay.', 'The scholarship will be awarded to whomever write the best essay.', 'C', '"Whoever" is correct because it is the subject of the clause "whoever writes the best essay."');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'hard', 'pronoun-clarity', 'The journalist interviewed the diplomat, who told her that his government''s position on the treaty, which they had supported for decades, was shifting due to pressure from their allies. Which revision best eliminates pronoun ambiguity?', 'No change', 'The journalist interviewed the diplomat, who told her that his government''s position on the treaty, which he had supported for decades, was shifting due to pressure from its allies.', 'The journalist interviewed the diplomat, who told the journalist that the diplomat''s government''s position on the treaty, which the government had supported for decades, was shifting due to pressure from allied nations.', 'The journalist interviewed the diplomat, whom told her that his government''s position on the treaty, which they had supported for decades, was shifting due to pressure from their allies.', 'C', 'Replacing ambiguous pronouns with specific nouns ("the journalist," "the diplomat''s government," "allied nations") eliminates all ambiguity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The committee chair informed the department heads that their recommendations, which they had submitted to the provost, who subsequently forwarded them to the board, would not be implemented this year. Which revision best improves clarity?', 'No change', 'The committee chair informed the department heads that the heads'' recommendations, which the heads had submitted to the provost—who subsequently forwarded the recommendations to the board—would not be implemented this year.', 'The committee chair informed the department heads that their recommendations, which they had submitted to the provost, whom subsequently forwarded them to the board, would not be implemented this year.', 'The committee chair informed the department heads that its recommendations, which it had submitted to the provost, who subsequently forwarded them to the board, would not be implemented this year.', 'B', 'Replacing the ambiguous pronouns with specific nouns and restructuring with an em dash for the nested clause greatly improves clarity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The researcher argued that the organism, which had adapted to its environment over millennia, could teach us about resilience, but this was disputed by her colleagues, who felt it oversimplified the evidence. Which revision clarifies "this" and "it"?', 'No change', 'The researcher argued that the organism, which had adapted to its environment over millennia, could teach us about resilience, but these were disputed by her colleagues, whom felt it oversimplified the evidence.', 'The researcher argued that the organism, which had adapted to its environment over millennia, could teach us about resilience, but it was disputed by her colleagues, who felt this oversimplified the evidence.', 'The researcher argued that the organism, which had adapted to its environment over millennia, could teach us about resilience, but this claim was disputed by her colleagues, who felt the argument oversimplified the evidence.', 'D', 'Replacing vague "this" with "this claim" and "it" with "the argument" eliminates ambiguity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The director told the screenwriter that the lead actor, who he had personally recruited for the role, thought that his vision for the film needed revision. Whose vision is unclear. Which revision best eliminates the ambiguity?', 'No change', 'The director told the screenwriter that the lead actor, whom he had personally recruited for the role, thought that its vision for the film needed revision.', 'The director told the screenwriter that the lead actor, who he had personally recruited for the role, thought that their vision for the film needed revision.', 'The director told the screenwriter that the lead actor, whom the director had personally recruited for the role, thought that the director''s vision for the film needed revision.', 'D', 'Replacing "he" with "the director" and "his" with "the director''s" eliminates the ambiguity about who recruited and whose vision.'),
('Grammar', 'hard', 'pronoun-clarity', 'The anthropologist, whom many consider to be the foremost expert in her field, published a paper about a tribe that maintained customs similar to those of its neighbors, though they differed significantly in their religious practices. Which revision best clarifies the pronouns?', 'No change', 'The anthropologist, whom many consider to be the foremost expert in her field, published a paper about a tribe that maintained customs similar to those of their neighbors, though they differed significantly in its religious practices.', 'The anthropologist, who many consider to be the foremost expert in her field, published a paper about a tribe that maintained customs similar to those of its neighbors, though they differed significantly in their religious practices.', 'The anthropologist, whom many consider to be the foremost expert in her field, published a paper about a tribe that maintained customs similar to those of its neighbors, though the tribe differed significantly from the neighbors in religious practices.', 'D', 'Replacing "they" and "their" with specific nouns clarifies which group differed and in what way.'),
('Grammar', 'hard', 'pronoun-clarity', 'The professor who the students most admired, and whom they frequently consulted about their research, announced his retirement. Is the who/whom usage correct?', 'No change', 'The professor whom the students most admired, and whom they frequently consulted about their research, announced his retirement.', 'The professor who the students most admired, and who they frequently consulted about their research, announced his retirement.', 'The professor whom the students most admired, and who they frequently consulted about their research, announced his retirement.', 'B', '"Whom" is correct in both instances: as the object of "admired" and as the object of "consulted."'),
('Grammar', 'hard', 'pronoun-clarity', 'The author dedicated the book to the teacher whom, she said, had inspired her to write and who she considered a mentor. Which choice corrects the pronoun usage?', 'No change', 'The author dedicated the book to the teacher who, she said, had inspired her to write and whom she considered a mentor.', 'The author dedicated the book to the teacher whom, she said, had inspired her to write and whom she considered a mentor.', 'The author dedicated the book to the teacher who, she said, had inspired her to write and who she considered a mentor.', 'B', '"Who" is the subject of "had inspired," and "whom" is the object of "considered."'),
('Grammar', 'hard', 'pronoun-clarity', 'The board voted to give the contract to whoever the committee recommended, but some members questioned whether they had properly vetted them. Which revision best eliminates the pronoun ambiguity?', 'No change', 'The board voted to give the contract to whomever the committee recommended, but some board members questioned whether the committee had properly vetted the candidates.', 'The board voted to give the contract to whoever the committee recommended, but some members questioned whether it had properly vetted them.', 'The board voted to give the contract to whom the committee recommended, but some members questioned whether they had properly vetted them.', 'B', '"Whomever" is the object of "recommended," and replacing vague pronouns with specific nouns clarifies who questioned and who was vetted.'),
('Grammar', 'hard', 'pronoun-clarity', 'The curator informed the donors that the paintings, which they had generously lent to the museum and that it had displayed prominently, would be returned to them by the end of the month. Which revision improves pronoun clarity?', 'No change', 'The curator informed the donors that the paintings, which the donors had generously lent to the museum and that the museum had displayed prominently, would be returned to the donors by the end of the month.', 'The curator informed the donors that the paintings, which they had generously lent to the museum and that they had displayed prominently, would be returned to them by the end of the month.', 'The curator informed the donors that the paintings, which it had generously lent to the museum and that they had displayed prominently, would be returned to it by the end of the month.', 'B', 'Replacing all pronouns with specific nouns eliminates any possibility of confusion about who lent, who displayed, and who receives.'),
('Grammar', 'hard', 'pronoun-clarity', 'The general counsel, to who the CEO had delegated responsibility for regulatory compliance, warned the board that whoever they appointed as the new auditor must be independent. Which choice corrects the pronoun errors?', 'No change', 'The general counsel, to whom the CEO had delegated responsibility for regulatory compliance, warned the board that whomever they appointed as the new auditor must be independent.', 'The general counsel, to whom the CEO had delegated responsibility for regulatory compliance, warned the board that whoever they appointed as the new auditor must be independent.', 'The general counsel, to who the CEO had delegated responsibility for regulatory compliance, warned the board that whomever they appointed as the new auditor must be independent.', 'C', '"To whom" is correct (object of preposition), and "whoever" is correct as the subject of "must be independent" even though it also serves as the object of "appointed."'),
('Grammar', 'hard', 'pronoun-clarity', 'The senators, whom the lobbyist had contacted earlier that week and who she hoped would support the bill, ultimately voted against it because they felt it contradicted their constituents'' wishes. Which choice corrects the pronoun?', 'No change', 'The senators, whom the lobbyist had contacted earlier that week and whom she hoped would support the bill, ultimately voted against it because they felt it contradicted their constituents'' wishes.', 'The senators, whom the lobbyist had contacted earlier that week and who she hoped would support the bill, ultimately voted against the measure because the senators felt the bill contradicted their constituents'' wishes.', 'The senators, who the lobbyist had contacted earlier that week and who she hoped would support the bill, ultimately voted against it because they felt it contradicted their constituents'' wishes.', 'C', '"Whom" is correct as object of "contacted"; "who" is correct as subject of "would support"; replacing later "it" with specific nouns prevents ambiguity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The investigation revealed that the officer, whom supervisors said they had repeatedly warned about his conduct, had continued the behavior that led to the complaint, which many felt should have been addressed sooner. Which revision best clarifies the pronouns?', 'No change', 'The investigation revealed that the officer, who supervisors said they had repeatedly warned about his conduct, had continued the behavior that led to the complaint, which many felt should have been addressed sooner.', 'The investigation revealed that the officer, whom supervisors said they had repeatedly warned about the officer''s conduct, had continued the behavior that led to the complaint—a matter many felt should have been addressed sooner.', 'The investigation revealed that the officer, whom supervisors said it had repeatedly warned about his conduct, had continued the behavior that led to the complaint, which many felt should have been addressed sooner.', 'C', 'Replacing "his" with "the officer''s" and using an em dash to clarify the "which" reference eliminates ambiguity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The therapist told the patient that he needed to be more open about his feelings, which he found difficult because he had never done it before. Which revision best eliminates pronoun ambiguity?', 'No change', 'The therapist told the patient that they needed to be more open about their feelings, which they found difficult because they had never done it before.', 'The therapist told the patient that the patient needed to be more open about the patient''s feelings—something the patient found difficult because he had never practiced such openness before.', 'The therapist told the patient that he needed to be more open about his feelings, which was difficult for him because he had never done them before.', 'C', 'Replacing the ambiguous pronouns with specific nouns and restructuring the clause eliminates the confusion about who needs to be open and who finds it difficult.'),
('Grammar', 'hard', 'pronoun-clarity', 'The editor informed the author that the publisher, who she had recommended and whom had agreed to review the manuscript, wanted to suggest revisions that would strengthen its argument. Which choice corrects the pronoun errors?', 'No change', 'The editor informed the author that the publisher, whom she had recommended and whom had agreed to review the manuscript, wanted to suggest revisions that would strengthen its argument.', 'The editor informed the author that the publisher, who she had recommended and who had agreed to review the manuscript, wanted to suggest revisions that would strengthen its argument.', 'The editor informed the author that the publisher, whom she had recommended and who had agreed to review the manuscript, wanted to suggest revisions that would strengthen the manuscript''s argument.', 'D', '"Whom" is correct as the object of "recommended"; "who" is correct as the subject of "had agreed"; replacing "its" with "the manuscript''s" clarifies the reference.'),
('Grammar', 'hard', 'pronoun-clarity', 'The architect showed the client a model of the building that he had designed, and he said that it reflected his vision for the project. Which revision best eliminates all ambiguity?', 'No change', 'The architect showed the client a model of the building that they had designed, and they said that it reflected their vision for the project.', 'The architect showed the client a model of the building that the architect had designed and explained that the model reflected the architect''s vision for the project.', 'The architect showed the client a model of the building which he had designed, and he said that it reflected his vision for the project.', 'C', 'Replacing all ambiguous pronouns with specific nouns and restructuring the sentence eliminates the confusion about who designed, who spoke, and whose vision.'),
('Grammar', 'hard', 'pronoun-clarity', 'The investors whom the startup founders had courted for months, and who the founders believed would provide crucial funding, ultimately declined because they felt the founders'' business plan, which they had helped revise, was still too risky. Which revision best clarifies the pronouns?', 'No change', 'The investors whom the startup founders had courted for months, and who the founders believed would provide crucial funding, ultimately declined because the investors felt the business plan—which the investors had helped revise—was still too risky.', 'The investors who the startup founders had courted for months, and whom the founders believed would provide crucial funding, ultimately declined because they felt the founders'' business plan, which they had helped revise, was still too risky.', 'The investors whom the startup founders had courted for months, and whom the founders believed would provide crucial funding, ultimately declined because they felt the founders'' business plan, which it had helped revise, was still too risky.', 'B', 'Replacing the ambiguous "they" instances with specific nouns and using an em dash clarifies who declined, who felt, and who revised.'),
('Grammar', 'hard', 'pronoun-clarity', 'The critic praised the novelist, who she felt had surpassed himself with his latest work, noting that he had managed to weave themes that resonated with them. Which revision best clarifies the pronoun references?', 'No change', 'The critic praised the novelist, whom she felt had surpassed himself with his latest work, noting that he had managed to weave themes that resonated with readers.', 'The critic praised the novelist, who the critic felt had surpassed himself with the latest work, noting that the novelist had managed to weave themes that resonated with readers.', 'The critic praised the novelist, who she felt had surpassed himself with his latest work, noting that he had managed to weave themes that resonated with her.', 'C', 'Replacing "she" with "the critic," the second "he" with "the novelist," and "them" with "readers" eliminates all ambiguity.'),
('Grammar', 'hard', 'pronoun-clarity', 'The principal told the superintendent that his staff had been demoralized by the new policy, which he believed undermined their authority, and that he would address it at the next board meeting. Which revision best eliminates the ambiguity?', 'No change', 'The principal told the superintendent that their staff had been demoralized by the new policy, which they believed undermined their authority, and that they would address it at the next board meeting.', 'The principal told the superintendent that the principal''s staff had been demoralized by the new policy, which the principal believed undermined the staff''s authority, and that the principal would address the issue at the next board meeting.', 'The principal told the superintendent that his staff had been demoralized by the new policy, which the principal believed undermined his authority, and that the principal would address it at the next board meeting.', 'C', 'Replacing every ambiguous pronoun with the specific noun it refers to eliminates all confusion about whose staff, whose belief, whose authority, and who will address the issue.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'easy', 'transitions', 'The weather forecast predicted rain. Moreover, we decided to have the picnic indoors. Which transition word best replaces the underlined word?', 'Therefore', 'Moreover', 'However', 'Similarly', 'A', '"Therefore" shows a cause-and-effect relationship: the rain forecast caused the decision to move indoors.'),
('Grammar', 'easy', 'transitions', 'The restaurant serves excellent food. In addition, the service is outstanding. Is this transition appropriate?', 'No change', 'However, the service is outstanding.', 'Nevertheless, the service is outstanding.', 'On the other hand, the service is outstanding.', 'A', '"In addition" correctly signals that a complementary point is being added.'),
('Grammar', 'easy', 'transitions', 'The team lost the first game. However, they won the championship. Is this transition appropriate?', 'No change', 'Therefore, they won the championship.', 'Moreover, they won the championship.', 'Similarly, they won the championship.', 'A', '"However" correctly signals a contrast between losing the first game and winning the championship.'),
('Grammar', 'easy', 'transitions', 'The experiment failed to produce the expected results. Similarly, the researchers revised their hypothesis. Which transition best fits?', 'Consequently', 'Similarly', 'Furthermore', 'Likewise', 'A', '"Consequently" correctly shows that the revision was a result of the failed experiment.'),
('Grammar', 'easy', 'transitions', 'She studied all night for the test. As a result, she earned the highest grade in the class. Is this transition appropriate?', 'No change', 'In contrast, she earned the highest grade in the class.', 'Nevertheless, she earned the highest grade in the class.', 'On the other hand, she earned the highest grade in the class.', 'A', '"As a result" correctly signals that the high grade was a consequence of studying.'),
('Grammar', 'easy', 'transitions', 'The park is beautiful in spring. For example, the cherry blossoms bloom along the main path. Is this transition appropriate?', 'No change', 'However, the cherry blossoms bloom along the main path.', 'Therefore, the cherry blossoms bloom along the main path.', 'In contrast, the cherry blossoms bloom along the main path.', 'A', '"For example" correctly introduces a specific illustration of the park''s beauty.'),
('Grammar', 'easy', 'transitions', 'The company raised salaries. Furthermore, they reduced working hours. Is this transition appropriate?', 'No change', 'Nevertheless, they reduced working hours.', 'In contrast, they reduced working hours.', 'However, they reduced working hours.', 'A', '"Furthermore" correctly adds another positive action taken by the company.'),
('Grammar', 'easy', 'transitions', 'Marcus is an excellent student. In contrast, he volunteers at the local shelter every weekend. Which transition best replaces the underlined phrase?', 'Additionally', 'However', 'In contrast', 'Nevertheless', 'A', '"Additionally" correctly signals that volunteering is another positive quality being added, not a contrast.'),
('Grammar', 'easy', 'transitions', 'The movie received poor reviews. Consequently, it became a box office hit. Which transition best replaces the underlined word?', 'Nevertheless', 'Consequently', 'Therefore', 'As a result', 'A', '"Nevertheless" signals a surprising outcome that contrasts with the poor reviews.'),
('Grammar', 'easy', 'transitions', 'The old bridge was structurally unsound. Therefore, the city decided to close it to traffic. Is this transition appropriate?', 'No change', 'However, the city decided to close it to traffic.', 'In addition, the city decided to close it to traffic.', 'For instance, the city decided to close it to traffic.', 'A', '"Therefore" correctly shows that closing the bridge was a logical result of its being unsound.'),
('Grammar', 'easy', 'transitions', 'The first experiment succeeded. Likewise, the second experiment produced positive results. Is this transition appropriate?', 'No change', 'Nevertheless, the second experiment produced positive results.', 'In contrast, the second experiment produced positive results.', 'However, the second experiment produced positive results.', 'A', '"Likewise" correctly signals that the second experiment had a similar outcome to the first.'),
('Grammar', 'easy', 'transitions', 'The store offers free delivery. Moreover, it provides a money-back guarantee. Is this transition appropriate?', 'No change', 'However, it provides a money-back guarantee.', 'In contrast, it provides a money-back guarantee.', 'Nevertheless, it provides a money-back guarantee.', 'A', '"Moreover" correctly introduces an additional benefit offered by the store.'),
('Grammar', 'easy', 'transitions', 'Cats are independent animals. On the other hand, dogs tend to be more social and loyal. Is this transition appropriate?', 'No change', 'Similarly, dogs tend to be more social and loyal.', 'Therefore, dogs tend to be more social and loyal.', 'As a result, dogs tend to be more social and loyal.', 'A', '"On the other hand" correctly introduces a contrast between the characteristics of cats and dogs.'),
('Grammar', 'easy', 'transitions', 'The trail was steep and muddy. Therefore, the hikers enjoyed the challenge. Which transition best replaces the underlined word?', 'Nonetheless', 'Therefore', 'Similarly', 'As a result', 'A', '"Nonetheless" signals that the hikers enjoyed the challenge despite the difficult conditions—a contrast, not a consequence.'),
('Grammar', 'easy', 'transitions', 'Regular exercise improves physical health. In addition, it has been shown to boost mental well-being. Is this transition appropriate?', 'No change', 'However, it has been shown to boost mental well-being.', 'In contrast, it has been shown to boost mental well-being.', 'Nevertheless, it has been shown to boost mental well-being.', 'A', '"In addition" correctly introduces a supplementary benefit of exercise.'),
('Grammar', 'easy', 'transitions', 'The speaker was not well known. However, her presentation captivated the entire audience. Is this transition appropriate?', 'No change', 'Therefore, her presentation captivated the entire audience.', 'Likewise, her presentation captivated the entire audience.', 'Moreover, her presentation captivated the entire audience.', 'A', '"However" correctly signals an unexpected contrast between the speaker''s obscurity and her captivating presentation.'),
('Grammar', 'easy', 'transitions', 'The company profits declined. In other words, the cost-cutting measures were ineffective. Is this transition appropriate?', 'No change', 'Specifically, the cost-cutting measures were ineffective.', 'For example, the cost-cutting measures were ineffective.', 'That is, the cost-cutting measures were ineffective.', 'D', '"That is" correctly restates or clarifies the implication of the profit decline.'),
('Grammar', 'easy', 'transitions', 'The students worked hard on their project. Meanwhile, the teacher prepared the grading rubric. Is this transition appropriate?', 'No change', 'Therefore, the teacher prepared the grading rubric.', 'However, the teacher prepared the grading rubric.', 'As a result, the teacher prepared the grading rubric.', 'A', '"Meanwhile" correctly indicates that two events were happening at the same time.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'medium', 'transitions', 'The archaeological evidence suggests that the settlement was abandoned gradually over several decades. Moreover, some historians argue that a catastrophic event triggered a sudden exodus. Which transition best replaces the underlined word?', 'However', 'Moreover', 'Therefore', 'Similarly', 'A', '"However" correctly introduces a contrasting interpretation from historians that contradicts the gradual abandonment theory.'),
('Grammar', 'medium', 'transitions', 'The new medication showed promising results in clinical trials; therefore, the FDA approved it for limited use. Specifically, the drug reduced symptoms in 78% of participants. Which transition is most appropriate at "Specifically"?', 'Specifically', 'In contrast', 'Nevertheless', 'Meanwhile', 'A', '"Specifically" correctly introduces a precise detail supporting the claim about promising results.'),
('Grammar', 'medium', 'transitions', 'The author''s first novel was celebrated for its vivid imagery and compelling characters. Her sophomore effort, in contrast, received mixed reviews due to its uneven pacing. Is this transition appropriate?', 'No change', 'Her sophomore effort, similarly, received mixed reviews due to its uneven pacing.', 'Her sophomore effort, consequently, received mixed reviews due to its uneven pacing.', 'Her sophomore effort, for instance, received mixed reviews due to its uneven pacing.', 'A', '"In contrast" correctly highlights the difference between the reception of the two novels.'),
('Grammar', 'medium', 'transitions', 'Urbanization has brought economic opportunities to many developing nations. Accordingly, it has also led to significant environmental degradation. Which transition best replaces the underlined word?', 'At the same time', 'Accordingly', 'As a result', 'In addition', 'A', '"At the same time" introduces a simultaneous and somewhat contrasting reality, which fits better than "accordingly."'),
('Grammar', 'medium', 'transitions', 'The study found that students who participated in extracurricular activities performed better academically. Furthermore, researchers noted that these students also reported higher levels of self-confidence. Is this transition appropriate?', 'No change', 'Conversely, researchers noted that these students also reported higher levels of self-confidence.', 'Instead, researchers noted that these students also reported higher levels of self-confidence.', 'On the contrary, researchers noted that these students also reported higher levels of self-confidence.', 'A', '"Furthermore" correctly adds a supporting finding to the original claim.'),
('Grammar', 'medium', 'transitions', 'Solar energy is becoming increasingly affordable and efficient. Nevertheless, many regions continue to rely heavily on fossil fuels. Is this transition appropriate?', 'No change', 'Consequently, many regions continue to rely heavily on fossil fuels.', 'Similarly, many regions continue to rely heavily on fossil fuels.', 'In addition, many regions continue to rely heavily on fossil fuels.', 'A', '"Nevertheless" correctly signals that the continued reliance on fossil fuels persists despite solar energy''s improvements.'),
('Grammar', 'medium', 'transitions', 'The CEO implemented sweeping organizational changes. As a result, employee morale initially declined. Subsequently, the new structure proved more efficient. Which transition is most appropriate at "Subsequently"?', 'Subsequently', 'In contrast', 'Instead', 'For example', 'A', '"Subsequently" correctly indicates a later development in the timeline following the initial decline in morale.'),
('Grammar', 'medium', 'transitions', 'The northern region experiences harsh winters with heavy snowfall. Conversely, the southern region enjoys mild temperatures year-round. Is this transition appropriate?', 'No change', 'Similarly, the southern region enjoys mild temperatures year-round.', 'Therefore, the southern region enjoys mild temperatures year-round.', 'Moreover, the southern region enjoys mild temperatures year-round.', 'A', '"Conversely" correctly highlights the geographic contrast in climate between the two regions.'),
('Grammar', 'medium', 'transitions', 'The volunteers worked tirelessly to rebuild homes destroyed by the hurricane. Nonetheless, many families remained displaced months after the storm. Is this transition appropriate?', 'No change', 'As a result, many families remained displaced months after the storm.', 'Likewise, many families remained displaced months after the storm.', 'In addition, many families remained displaced months after the storm.', 'A', '"Nonetheless" correctly introduces a disappointing reality that persists despite the volunteers'' efforts.'),
('Grammar', 'medium', 'transitions', 'The company invested millions in research and development. Similarly, it slashed its marketing budget. Which transition best replaces the underlined word?', 'Meanwhile', 'Similarly', 'Therefore', 'Likewise', 'A', '"Meanwhile" signals that two contrasting actions happened in parallel: investing in R&D while cutting marketing.'),
('Grammar', 'medium', 'transitions', 'The proposed highway expansion would reduce commute times for thousands of residents. On the other hand, it would require the demolition of several historic buildings. Is this transition appropriate?', 'No change', 'Moreover, it would require the demolition of several historic buildings.', 'Consequently, it would require the demolition of several historic buildings.', 'In addition, it would require the demolition of several historic buildings.', 'A', '"On the other hand" correctly introduces a significant drawback that contrasts with the benefit.'),
('Grammar', 'medium', 'transitions', 'The patient''s condition improved markedly after the new treatment was administered. Indeed, follow-up tests showed that the infection had been completely eradicated. Is this transition appropriate?', 'No change', 'However, follow-up tests showed that the infection had been completely eradicated.', 'Instead, follow-up tests showed that the infection had been completely eradicated.', 'In contrast, follow-up tests showed that the infection had been completely eradicated.', 'A', '"Indeed" correctly emphasizes and confirms the claim about the patient''s improvement.'),
('Grammar', 'medium', 'transitions', 'The factory produces high-quality goods at competitive prices. Granted, its labor practices have drawn criticism from human rights organizations. Is this transition appropriate?', 'No change', 'For example, its labor practices have drawn criticism from human rights organizations.', 'Furthermore, its labor practices have drawn criticism from human rights organizations.', 'In other words, its labor practices have drawn criticism from human rights organizations.', 'A', '"Granted" correctly concedes a valid counterpoint while acknowledging the preceding positive claim.'),
('Grammar', 'medium', 'transitions', 'The school board approved a budget increase for arts education. For instance, funding for music programs will double next year. Is this transition appropriate?', 'No change', 'Nevertheless, funding for music programs will double next year.', 'In contrast, funding for music programs will double next year.', 'However, funding for music programs will double next year.', 'A', '"For instance" correctly introduces a specific example of how the budget increase will be applied.'),
('Grammar', 'medium', 'transitions', 'Early agricultural societies depended on predictable rainfall. In the same way, modern farmers increasingly rely on advanced irrigation technology. Which transition best replaces the underlined phrase?', 'By contrast', 'In the same way', 'As a result', 'Similarly', 'A', '"By contrast" correctly highlights how modern farming differs from early agriculture in its methods, despite both depending on water.'),
('Grammar', 'medium', 'transitions', 'The novelist''s work has been praised for its psychological depth. Consequently, some critics find the plots overly slow and introspective. Which transition best replaces the underlined word?', 'Admittedly', 'Consequently', 'Therefore', 'As a result', 'A', '"Admittedly" correctly concedes a criticism while acknowledging that praise is also deserved—this is not a consequence.'),
('Grammar', 'medium', 'transitions', 'The government increased infrastructure spending to stimulate economic growth. Accordingly, unemployment rates began to decline within six months. Is this transition appropriate?', 'No change', 'Nevertheless, unemployment rates began to decline within six months.', 'In contrast, unemployment rates began to decline within six months.', 'On the other hand, unemployment rates began to decline within six months.', 'A', '"Accordingly" correctly shows that the decline in unemployment was a logical result of the increased spending.'),
('Grammar', 'medium', 'transitions', 'The documentary presents compelling evidence for climate change. Above all, the final segment, which features testimony from displaced communities, is deeply moving. Is this transition appropriate?', 'No change', 'In contrast, the final segment, which features testimony from displaced communities, is deeply moving.', 'However, the final segment, which features testimony from displaced communities, is deeply moving.', 'For instance, the final segment, which features testimony from displaced communities, is deeply moving.', 'A', '"Above all" correctly introduces the most important or impactful element of the documentary.');
INSERT INTO sat_questions (category, difficulty, subtopic, question, option_a, option_b, option_c, option_d, correct, explanation) VALUES
('Grammar', 'hard', 'transitions', 'The philosopher''s early work focused on the nature of consciousness, arguing that subjective experience could not be reduced to neural activity. ______, his later writings adopted a more conciliatory stance, acknowledging that neuroscience had made significant progress in mapping the brain''s role in perception. Which transition best fills the blank?', 'Nevertheless', 'Moreover', 'Similarly', 'Therefore', 'A', '"Nevertheless" correctly signals a shift from his early absolutist position to his later, more flexible stance.'),
('Grammar', 'hard', 'transitions', 'The archaeological record indicates that the Mayan civilization experienced a prolonged drought during the ninth century. ______, recent isotope analyses of stalagmites from caves in the Yucatan Peninsula corroborate the timing and severity of this dry period. Which transition best fills the blank?', 'In contrast', 'However', 'Indeed', 'Instead', 'C', '"Indeed" correctly emphasizes that the isotope data confirms and strengthens the existing evidence of drought.'),
('Grammar', 'hard', 'transitions', 'The quantum computing industry has attracted billions in venture capital, with major technology companies racing to achieve computational supremacy. ______, practical quantum computers capable of outperforming classical machines on real-world problems remain years away, according to most experts. Which transition best fills the blank?', 'That said', 'Furthermore', 'Similarly', 'Consequently', 'A', '"That said" correctly introduces a caveat that tempers the enthusiastic investment narrative.'),
('Grammar', 'hard', 'transitions', 'The Renaissance marked a period of extraordinary artistic achievement in Europe, with masters like Leonardo da Vinci and Michelangelo pushing the boundaries of visual expression. ______, this era also witnessed profound advances in science and philosophy, as thinkers like Galileo and Erasmus challenged established orthodoxies. Which transition best fills the blank?', 'However', 'In contrast', 'Simultaneously', 'As a result', 'C', '"Simultaneously" correctly indicates that artistic and intellectual achievements occurred in parallel during the same era.'),
('Grammar', 'hard', 'transitions', 'The longitudinal study tracked over five thousand participants for twenty years, making it one of the most comprehensive investigations of its kind. ______, the study''s reliance on self-reported data introduces a significant methodological limitation. Which transition best fills the blank?', 'Even so', 'Moreover', 'In addition', 'Similarly', 'A', '"Even so" correctly concedes a limitation despite the study''s comprehensive scope.'),
('Grammar', 'hard', 'transitions', 'Historical accounts have long attributed the fall of Constantinople to the military prowess of the Ottoman forces. ______, recent scholarship has drawn attention to the role of internal political divisions and economic decline in weakening the Byzantine Empire''s defenses. Which transition best fills the blank?', 'More recently, however', 'Similarly', 'As a result', 'In addition', 'A', '"More recently, however" correctly signals a shift in scholarly interpretation that challenges or supplements the traditional narrative.'),
('Grammar', 'hard', 'transitions', 'The gene-editing tool CRISPR-Cas9 has revolutionized molecular biology by enabling precise modifications to DNA sequences. ______, its application in human embryos has raised profound ethical concerns that the scientific community has yet to fully resolve. Which transition best fills the blank?', 'At the same time', 'Similarly', 'Therefore', 'In addition', 'A', '"At the same time" correctly introduces a simultaneous ethical concern that complicates the positive technological narrative.'),
('Grammar', 'hard', 'transitions', 'The economist argued that austerity measures during recessions exacerbate unemployment and slow recovery. ______, she acknowledged that unchecked deficit spending poses its own long-term risks to fiscal stability. Which transition best fills the blank?', 'Nonetheless', 'Furthermore', 'Similarly', 'As a result', 'A', '"Nonetheless" correctly shows that the economist conceded a valid counterpoint to her main argument.'),
('Grammar', 'hard', 'transitions', 'Proponents of standardized testing argue that such assessments provide objective data for comparing student achievement across schools and districts. ______, critics contend that these tests incentivize rote memorization at the expense of critical thinking and creativity. Which transition best fills the blank?', 'In contrast', 'Moreover', 'Consequently', 'Similarly', 'A', '"In contrast" correctly introduces the opposing perspective of critics against proponents.'),
('Grammar', 'hard', 'transitions', 'The company''s aggressive expansion strategy initially alarmed investors, who feared that the rapid growth would strain the firm''s resources. ______, the gamble paid off: within three years, revenue had tripled and the company had established a dominant market position. Which transition best fills the blank?', 'In the end, however', 'Moreover', 'Similarly', 'As a result', 'A', '"In the end, however" correctly signals that the outcome contradicted the initial fears.'),
('Grammar', 'hard', 'transitions', 'The coral reefs of the Great Barrier Reef support an extraordinarily diverse ecosystem, providing habitat for thousands of marine species. ______, rising ocean temperatures and acidification threaten to decimate these reefs within decades if current trends continue. Which transition best fills the blank?', 'However', 'For example', 'In addition', 'Similarly', 'A', '"However" correctly introduces a threat that contrasts with the positive ecological role of the reefs.'),
('Grammar', 'hard', 'transitions', 'The initial phase of the clinical trial yielded encouraging results, with the experimental drug showing a statistically significant reduction in tumor size. ______, the Phase III trial, which enrolled a larger and more diverse patient population, confirmed these findings and revealed an even greater treatment effect than anticipated. Which transition best fills the blank?', 'In contrast', 'Consequently', 'Subsequently', 'Nevertheless', 'C', '"Subsequently" correctly indicates the temporal sequence from the initial phase to the later Phase III trial.'),
('Grammar', 'hard', 'transitions', 'The prevailing theory held that the extinction of the dinosaurs was caused by a single catastrophic asteroid impact. ______, a growing body of evidence suggests that massive volcanic eruptions in what is now India had already weakened many species before the asteroid struck. Which transition best fills the blank?', 'However', 'Moreover', 'As a result', 'Similarly', 'A', '"However" correctly introduces evidence that complicates or challenges the single-cause asteroid theory.'),
('Grammar', 'hard', 'transitions', 'Indigenous land management practices, including controlled burns and rotational farming, sustained ecosystems for thousands of years. ______, modern conservation efforts have increasingly incorporated these traditional techniques, recognizing their ecological value. Which transition best fills the blank?', 'Accordingly', 'In contrast', 'Nevertheless', 'Similarly', 'A', '"Accordingly" correctly shows that modern conservation adopted these techniques as a logical response to their proven effectiveness.'),
('Grammar', 'hard', 'transitions', 'The author''s memoir offers a vivid account of growing up in rural Appalachia, capturing the region''s beauty and hardship with equal eloquence. ______, the work transcends regional specificity, speaking to universal themes of resilience, family, and the search for identity. Which transition best fills the blank?', 'More broadly', 'However', 'In contrast', 'Instead', 'A', '"More broadly" correctly signals an expansion from the specific (Appalachia) to the universal themes.'),
('Grammar', 'hard', 'transitions', 'The treaty was designed to reduce carbon emissions by 40% over the next decade—an ambitious target by any standard. ______, most signatory nations have fallen short of even their interim commitments, casting doubt on the agreement''s long-term viability. Which transition best fills the blank?', 'To date, however', 'Moreover', 'Similarly', 'Furthermore', 'A', '"To date, however" correctly introduces a disappointing reality that contrasts with the ambitious goal, while specifying the temporal frame.'),
('Grammar', 'hard', 'transitions', 'The astronomer''s observations of distant galaxies challenged the prevailing cosmological model, suggesting that the universe''s expansion was accelerating rather than decelerating. ______, these findings earned her the Nobel Prize and prompted a fundamental reassessment of dark energy''s role in shaping the cosmos. Which transition best fills the blank?', 'Ultimately', 'In contrast', 'Nevertheless', 'Instead', 'A', '"Ultimately" correctly signals the final outcome of a significant finding—recognition and scientific reassessment.'),
('Grammar', 'hard', 'transitions', 'The ancient city''s water management system was remarkably sophisticated, featuring aqueducts, reservoirs, and a network of underground channels. ______, this infrastructure enabled the city to sustain a population of over one hundred thousand in an arid climate where rainfall was scarce. Which transition best fills the blank?', 'However', 'In other words', 'In effect', 'By contrast', 'C', '"In effect" correctly introduces the practical outcome or real-world consequence of the sophisticated system.');
